window.ASBAB_NUZUL_CACHE["8"] = {"asbab_nuzul":{"1":[{"ar":"عَنْ سَعْدٍ رضي الله عنه: أَنَّهُ نَزَلَتْ فِيهِ آيَاتٌ مِنْ الْقُرْآنِ، قَالَ: حَلَفَتْ أُمُّ سَعْدٍ أَنْ لَا تُكَلِّمَهُ أَبَداً حَتَّى يَكْفُرَ بِدِينِهِ، وَلَا تَأْكُلَ وَلَا تَشْرَبَ، قَالَتْ: زَعَمْتَ أَنَّ اللهَ وَصَّاكَ بِوَالِدَيْكَ، وَأَنَا أُمُّكَ وَأَنَا آمُرُكَ بِهَذَا. قَالَ: مَكَثَتْ ثَلاثاً حَتَّى غُشِيَ عَلَيْهَا مِنْ الْجَهْدِ، فَقَامَ ابْنٌ لَهَا يُقَالُ لَهُ عُمَارَة، فَسَقَاهَا، فَجَعَلَتْ تَدْعُو عَلَى سَعْدٍ، فَأَنْزَلَ اللهُ عز و جل فِي الْقُرْآنِ هَذِهِ الْآيَةَ: { وَوَصَّيْنَا ٱلْإِنسَـٰنَ بِوَٰلِدَيْهِ حُسْنًا ۖ وَإِن جَـٰهَدَاكَ لِتُشْرِكَ بِى } وفيها { وَصَاحِبْهُمَا فِى ٱلدُّنْيَا مَعْرُوفًا ۖ }.\n\nقَالَ: وَأَصَابَ رَسُولُ اللهِ ﷺ غَنِيمَةً عَظِيمَةً، فَإِذَا فِيهَا سَيْفٌ فَأَخَذْتُهُ، فَأَتَيْتُ بِهِ الرَّسُولَ ﷺ، فَقُلْتُ: نَفِّلْنِي هَذَا السَّيْفَ، فَأَنَا مَنْ قَدْ عَلِمْتَ حَالَهُ. فَقَالَ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، فَانْطَلَقْتُ، حَتَّى إِذَا أَرَدْتُ أَنْ أُلْقِيَهُ فِي الْقَبْضِ لَامَتْنِي نَفْسِي، فَرَجَعْتُ إِلَيْهِ، فَقُلْتُ: أَعْطِنِيهِ، قَالَ: فَشَدَّ لِي صَوْتَهُ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، قَالَ: فَأَنْزَلَ اللهُ عز و جل: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ }. قَالَ: وَمَرِضْتُ فَأَرْسَلْتُ إِلَى النَّبِيِّ ﷺ فَأَتَانِي، فَقُلْتُ: دَعْنِي أَقْسِمْ مَالِي حَيْثُ شِئْتُ، قَالَ: فَأَبَى، قُلْتُ: فَالنِّصْفَ، قَالَ: فَأَبَى، قُلْتُ: فَالثُّلُثَ، قَالَ: فَسَكَتَ، فَكَانَ بَعْدُ، الثُّلُثُ جَائِزاً.\n\nقَالَ: وَأَتَيْتُ عَلَى نَفَرٍ مِنْ الْأَنْصَارِ وَالمُهَاجِرِينَ، فَقَالُوا: تَعَالَ نُطْعِمْكَ\nوَنَسْقِكَ خَمْراً، وَذَلِكَ قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ، قَالَ: فَأَتَيْتُهُمْ فِي حَشٍّ - وَالْحَشُّ الْبُسْتَانُ - فَإِذَا رَأْسُ جَزُورٍ مَشْوِيٌّ عِنْدَهُمْ، وَزِقٌ مِنْ خَمْرٍ، قَالَ: فَأَكَلْتُ وَشَرِبْتُ مَعَهُمْ، قَالَ: فَذَكَرْتُ الْأَنْصَارَ وَالْمُهَاجِرِينَ عِنْدَهُمْ، فَقُلْتُ: الْمُهَاجِرُونَ خَيْرٌ مِنْ الْأَنْصَارِ، قَالَ: فَأَخَذَ رَجُلٌ أَحَدَ لَحْيَيْ الرَّأْسِ فَضَرَبَنِي بِهِ فَجَرَحَ بِأَنْفِي، فَأَتَيْتُ رَسُولَ اللهِ ﷺ فَأَخْبَرْتُهُ، فَأَنْزَلَ اللهُ عز و جل فِيَّ - يَعْنِي نَفْسَهُ - شَأْنَ الْخَمْرِ: { إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ }. واللفظ لمسلم في الفضائل.","id":""},{"ar":"وللآية سبب آخر فقد جاء: عَنْ أَبِي أُمَامَةَ، عَنْ عُبَادَةَ بْنِ الصَّامِتِ رضي الله عنه قَالَ: خَرَجْنَا مَعَ النَّبِيِّ ﷺ فَشَهِدْتُ مَعَهُ بَدْراً، فَالْتَقَى النَّاسُ فَهَزَمَ اللهُ تَبَارَكَ وَتَعَالَى الْعَدُوَّ، فَانْطَلَقَتْ طَائِفَةٌ فِي آثَارِهِمْ يَهْزِمُونَ وَيَقْتُلُونَ، فَأَكَبَّتْ طَائِفَةٌ عَلَى الْعَسْكَرِ يَحْوُونَهُ وَيَجْمَعُونَهُ، وَأَحْدَقَتْ طَائِفَةٌ بِرَسُولِ اللهِ ﷺ لَا يُصِيبُ الْعَدُوُّ مِنْهُ غِرَّةً، حَتَّى إِذَا كَانَ اللَّيْلُ، وَفَاءَ النَّاسُ بَعْضُهُمْ إِلَى بَعْضٍ، قَالَ الَّذِينَ جَمَعُوا الْغَنَائِمَ: نَحْنُ حَوَيْنَاهَا وَجَمَعْنَاهَا، فَلَيْسَ لِأَحَدٍ فِيهَا نَصِيبٌ، وَقَالَ الَّذِينَ خَرَجُوا فِي طَلَبِ الْعَدُوِّ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا، نَحْنُ نَفَيْنَا عَنْهَا الْعَدُوَّ وَهَزَمْنَاهُمْ، وَقَالَ الَّذِينَ أَحْدَقُوا بِرَسُولِ اللهِ ﷺ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا نَحْنُ أَحْدَقْنَا بِرَسُولِ اللهِ ﷺ وَخِفْنَا أَنْ يُصِيبَ الْعَدُوُّ مِنْهُ غِرَّةً، وَاشْتَغَلْنَا بِهِ.\n\nفَنَزَلَتْ: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ قُلِ ٱلْأَنفَالُ لِلَّهِ وَٱلرَّسُولِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَصْلِحُوا۟ ذَاتَ بَيْنِكُمْ ۖ } فَقَسَمَهَا رَسُولُ الله ﷺ عَلَى فَوَاقٍ بَيْنَ الْمُسْلِمِينَ، قَالَ: وَكَانَ رَسُولُ اللهِ ﷺ إِذَا أَغَارَ فِي أَرْضِ الْعَدُوِّ، نَفَلَ الرُّبُعَ، وَإِذَا أَقْبَلَ رَاجِعاً وَكُلَّ النَّاسِ نَفَلَ الثُّلُثَ، وَكَانَ يَكْرَهُ الْأَنْفَالَ وَيَقُولُ: لِيَرُدَّ قَوِيُّ الْمُؤْمِنِينَ عَلَى ضَعِيفِهِمْ السَّوَاءِ. واللفظ لأحمد.\n\nوله شاهد من حديث جاء عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما.","id":""}],"2":[{"ar":"عَنْ سَعْدٍ رضي الله عنه: أَنَّهُ نَزَلَتْ فِيهِ آيَاتٌ مِنْ الْقُرْآنِ، قَالَ: حَلَفَتْ أُمُّ سَعْدٍ أَنْ لَا تُكَلِّمَهُ أَبَداً حَتَّى يَكْفُرَ بِدِينِهِ، وَلَا تَأْكُلَ وَلَا تَشْرَبَ، قَالَتْ: زَعَمْتَ أَنَّ اللهَ وَصَّاكَ بِوَالِدَيْكَ، وَأَنَا أُمُّكَ وَأَنَا آمُرُكَ بِهَذَا. قَالَ: مَكَثَتْ ثَلاثاً حَتَّى غُشِيَ عَلَيْهَا مِنْ الْجَهْدِ، فَقَامَ ابْنٌ لَهَا يُقَالُ لَهُ عُمَارَة، فَسَقَاهَا، فَجَعَلَتْ تَدْعُو عَلَى سَعْدٍ، فَأَنْزَلَ اللهُ عز و جل فِي الْقُرْآنِ هَذِهِ الْآيَةَ: { وَوَصَّيْنَا ٱلْإِنسَـٰنَ بِوَٰلِدَيْهِ حُسْنًا ۖ وَإِن جَـٰهَدَاكَ لِتُشْرِكَ بِى } وفيها { وَصَاحِبْهُمَا فِى ٱلدُّنْيَا مَعْرُوفًا ۖ }.\n\nقَالَ: وَأَصَابَ رَسُولُ اللهِ ﷺ غَنِيمَةً عَظِيمَةً، فَإِذَا فِيهَا سَيْفٌ فَأَخَذْتُهُ، فَأَتَيْتُ بِهِ الرَّسُولَ ﷺ، فَقُلْتُ: نَفِّلْنِي هَذَا السَّيْفَ، فَأَنَا مَنْ قَدْ عَلِمْتَ حَالَهُ. فَقَالَ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، فَانْطَلَقْتُ، حَتَّى إِذَا أَرَدْتُ أَنْ أُلْقِيَهُ فِي الْقَبْضِ لَامَتْنِي نَفْسِي، فَرَجَعْتُ إِلَيْهِ، فَقُلْتُ: أَعْطِنِيهِ، قَالَ: فَشَدَّ لِي صَوْتَهُ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، قَالَ: فَأَنْزَلَ اللهُ عز و جل: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ }. قَالَ: وَمَرِضْتُ فَأَرْسَلْتُ إِلَى النَّبِيِّ ﷺ فَأَتَانِي، فَقُلْتُ: دَعْنِي أَقْسِمْ مَالِي حَيْثُ شِئْتُ، قَالَ: فَأَبَى، قُلْتُ: فَالنِّصْفَ، قَالَ: فَأَبَى، قُلْتُ: فَالثُّلُثَ، قَالَ: فَسَكَتَ، فَكَانَ بَعْدُ، الثُّلُثُ جَائِزاً.\n\nقَالَ: وَأَتَيْتُ عَلَى نَفَرٍ مِنْ الْأَنْصَارِ وَالمُهَاجِرِينَ، فَقَالُوا: تَعَالَ نُطْعِمْكَ\nوَنَسْقِكَ خَمْراً، وَذَلِكَ قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ، قَالَ: فَأَتَيْتُهُمْ فِي حَشٍّ - وَالْحَشُّ الْبُسْتَانُ - فَإِذَا رَأْسُ جَزُورٍ مَشْوِيٌّ عِنْدَهُمْ، وَزِقٌ مِنْ خَمْرٍ، قَالَ: فَأَكَلْتُ وَشَرِبْتُ مَعَهُمْ، قَالَ: فَذَكَرْتُ الْأَنْصَارَ وَالْمُهَاجِرِينَ عِنْدَهُمْ، فَقُلْتُ: الْمُهَاجِرُونَ خَيْرٌ مِنْ الْأَنْصَارِ، قَالَ: فَأَخَذَ رَجُلٌ أَحَدَ لَحْيَيْ الرَّأْسِ فَضَرَبَنِي بِهِ فَجَرَحَ بِأَنْفِي، فَأَتَيْتُ رَسُولَ اللهِ ﷺ فَأَخْبَرْتُهُ، فَأَنْزَلَ اللهُ عز و جل فِيَّ - يَعْنِي نَفْسَهُ - شَأْنَ الْخَمْرِ: { إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ }. واللفظ لمسلم في الفضائل.","id":""},{"ar":"وللآية سبب آخر فقد جاء: عَنْ أَبِي أُمَامَةَ، عَنْ عُبَادَةَ بْنِ الصَّامِتِ رضي الله عنه قَالَ: خَرَجْنَا مَعَ النَّبِيِّ ﷺ فَشَهِدْتُ مَعَهُ بَدْراً، فَالْتَقَى النَّاسُ فَهَزَمَ اللهُ تَبَارَكَ وَتَعَالَى الْعَدُوَّ، فَانْطَلَقَتْ طَائِفَةٌ فِي آثَارِهِمْ يَهْزِمُونَ وَيَقْتُلُونَ، فَأَكَبَّتْ طَائِفَةٌ عَلَى الْعَسْكَرِ يَحْوُونَهُ وَيَجْمَعُونَهُ، وَأَحْدَقَتْ طَائِفَةٌ بِرَسُولِ اللهِ ﷺ لَا يُصِيبُ الْعَدُوُّ مِنْهُ غِرَّةً، حَتَّى إِذَا كَانَ اللَّيْلُ، وَفَاءَ النَّاسُ بَعْضُهُمْ إِلَى بَعْضٍ، قَالَ الَّذِينَ جَمَعُوا الْغَنَائِمَ: نَحْنُ حَوَيْنَاهَا وَجَمَعْنَاهَا، فَلَيْسَ لِأَحَدٍ فِيهَا نَصِيبٌ، وَقَالَ الَّذِينَ خَرَجُوا فِي طَلَبِ الْعَدُوِّ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا، نَحْنُ نَفَيْنَا عَنْهَا الْعَدُوَّ وَهَزَمْنَاهُمْ، وَقَالَ الَّذِينَ أَحْدَقُوا بِرَسُولِ اللهِ ﷺ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا نَحْنُ أَحْدَقْنَا بِرَسُولِ اللهِ ﷺ وَخِفْنَا أَنْ يُصِيبَ الْعَدُوُّ مِنْهُ غِرَّةً، وَاشْتَغَلْنَا بِهِ.\n\nفَنَزَلَتْ: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ قُلِ ٱلْأَنفَالُ لِلَّهِ وَٱلرَّسُولِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَصْلِحُوا۟ ذَاتَ بَيْنِكُمْ ۖ } فَقَسَمَهَا رَسُولُ الله ﷺ عَلَى فَوَاقٍ بَيْنَ الْمُسْلِمِينَ، قَالَ: وَكَانَ رَسُولُ اللهِ ﷺ إِذَا أَغَارَ فِي أَرْضِ الْعَدُوِّ، نَفَلَ الرُّبُعَ، وَإِذَا أَقْبَلَ رَاجِعاً وَكُلَّ النَّاسِ نَفَلَ الثُّلُثَ، وَكَانَ يَكْرَهُ الْأَنْفَالَ وَيَقُولُ: لِيَرُدَّ قَوِيُّ الْمُؤْمِنِينَ عَلَى ضَعِيفِهِمْ السَّوَاءِ. واللفظ لأحمد.\n\nوله شاهد من حديث جاء عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما.","id":""}],"3":[{"ar":"عَنْ سَعْدٍ رضي الله عنه: أَنَّهُ نَزَلَتْ فِيهِ آيَاتٌ مِنْ الْقُرْآنِ، قَالَ: حَلَفَتْ أُمُّ سَعْدٍ أَنْ لَا تُكَلِّمَهُ أَبَداً حَتَّى يَكْفُرَ بِدِينِهِ، وَلَا تَأْكُلَ وَلَا تَشْرَبَ، قَالَتْ: زَعَمْتَ أَنَّ اللهَ وَصَّاكَ بِوَالِدَيْكَ، وَأَنَا أُمُّكَ وَأَنَا آمُرُكَ بِهَذَا. قَالَ: مَكَثَتْ ثَلاثاً حَتَّى غُشِيَ عَلَيْهَا مِنْ الْجَهْدِ، فَقَامَ ابْنٌ لَهَا يُقَالُ لَهُ عُمَارَة، فَسَقَاهَا، فَجَعَلَتْ تَدْعُو عَلَى سَعْدٍ، فَأَنْزَلَ اللهُ عز و جل فِي الْقُرْآنِ هَذِهِ الْآيَةَ: { وَوَصَّيْنَا ٱلْإِنسَـٰنَ بِوَٰلِدَيْهِ حُسْنًا ۖ وَإِن جَـٰهَدَاكَ لِتُشْرِكَ بِى } وفيها { وَصَاحِبْهُمَا فِى ٱلدُّنْيَا مَعْرُوفًا ۖ }.\n\nقَالَ: وَأَصَابَ رَسُولُ اللهِ ﷺ غَنِيمَةً عَظِيمَةً، فَإِذَا فِيهَا سَيْفٌ فَأَخَذْتُهُ، فَأَتَيْتُ بِهِ الرَّسُولَ ﷺ، فَقُلْتُ: نَفِّلْنِي هَذَا السَّيْفَ، فَأَنَا مَنْ قَدْ عَلِمْتَ حَالَهُ. فَقَالَ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، فَانْطَلَقْتُ، حَتَّى إِذَا أَرَدْتُ أَنْ أُلْقِيَهُ فِي الْقَبْضِ لَامَتْنِي نَفْسِي، فَرَجَعْتُ إِلَيْهِ، فَقُلْتُ: أَعْطِنِيهِ، قَالَ: فَشَدَّ لِي صَوْتَهُ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، قَالَ: فَأَنْزَلَ اللهُ عز و جل: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ }. قَالَ: وَمَرِضْتُ فَأَرْسَلْتُ إِلَى النَّبِيِّ ﷺ فَأَتَانِي، فَقُلْتُ: دَعْنِي أَقْسِمْ مَالِي حَيْثُ شِئْتُ، قَالَ: فَأَبَى، قُلْتُ: فَالنِّصْفَ، قَالَ: فَأَبَى، قُلْتُ: فَالثُّلُثَ، قَالَ: فَسَكَتَ، فَكَانَ بَعْدُ، الثُّلُثُ جَائِزاً.\n\nقَالَ: وَأَتَيْتُ عَلَى نَفَرٍ مِنْ الْأَنْصَارِ وَالمُهَاجِرِينَ، فَقَالُوا: تَعَالَ نُطْعِمْكَ\nوَنَسْقِكَ خَمْراً، وَذَلِكَ قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ، قَالَ: فَأَتَيْتُهُمْ فِي حَشٍّ - وَالْحَشُّ الْبُسْتَانُ - فَإِذَا رَأْسُ جَزُورٍ مَشْوِيٌّ عِنْدَهُمْ، وَزِقٌ مِنْ خَمْرٍ، قَالَ: فَأَكَلْتُ وَشَرِبْتُ مَعَهُمْ، قَالَ: فَذَكَرْتُ الْأَنْصَارَ وَالْمُهَاجِرِينَ عِنْدَهُمْ، فَقُلْتُ: الْمُهَاجِرُونَ خَيْرٌ مِنْ الْأَنْصَارِ، قَالَ: فَأَخَذَ رَجُلٌ أَحَدَ لَحْيَيْ الرَّأْسِ فَضَرَبَنِي بِهِ فَجَرَحَ بِأَنْفِي، فَأَتَيْتُ رَسُولَ اللهِ ﷺ فَأَخْبَرْتُهُ، فَأَنْزَلَ اللهُ عز و جل فِيَّ - يَعْنِي نَفْسَهُ - شَأْنَ الْخَمْرِ: { إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ }. واللفظ لمسلم في الفضائل.","id":""},{"ar":"وللآية سبب آخر فقد جاء: عَنْ أَبِي أُمَامَةَ، عَنْ عُبَادَةَ بْنِ الصَّامِتِ رضي الله عنه قَالَ: خَرَجْنَا مَعَ النَّبِيِّ ﷺ فَشَهِدْتُ مَعَهُ بَدْراً، فَالْتَقَى النَّاسُ فَهَزَمَ اللهُ تَبَارَكَ وَتَعَالَى الْعَدُوَّ، فَانْطَلَقَتْ طَائِفَةٌ فِي آثَارِهِمْ يَهْزِمُونَ وَيَقْتُلُونَ، فَأَكَبَّتْ طَائِفَةٌ عَلَى الْعَسْكَرِ يَحْوُونَهُ وَيَجْمَعُونَهُ، وَأَحْدَقَتْ طَائِفَةٌ بِرَسُولِ اللهِ ﷺ لَا يُصِيبُ الْعَدُوُّ مِنْهُ غِرَّةً، حَتَّى إِذَا كَانَ اللَّيْلُ، وَفَاءَ النَّاسُ بَعْضُهُمْ إِلَى بَعْضٍ، قَالَ الَّذِينَ جَمَعُوا الْغَنَائِمَ: نَحْنُ حَوَيْنَاهَا وَجَمَعْنَاهَا، فَلَيْسَ لِأَحَدٍ فِيهَا نَصِيبٌ، وَقَالَ الَّذِينَ خَرَجُوا فِي طَلَبِ الْعَدُوِّ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا، نَحْنُ نَفَيْنَا عَنْهَا الْعَدُوَّ وَهَزَمْنَاهُمْ، وَقَالَ الَّذِينَ أَحْدَقُوا بِرَسُولِ اللهِ ﷺ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا نَحْنُ أَحْدَقْنَا بِرَسُولِ اللهِ ﷺ وَخِفْنَا أَنْ يُصِيبَ الْعَدُوُّ مِنْهُ غِرَّةً، وَاشْتَغَلْنَا بِهِ.\n\nفَنَزَلَتْ: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ قُلِ ٱلْأَنفَالُ لِلَّهِ وَٱلرَّسُولِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَصْلِحُوا۟ ذَاتَ بَيْنِكُمْ ۖ } فَقَسَمَهَا رَسُولُ الله ﷺ عَلَى فَوَاقٍ بَيْنَ الْمُسْلِمِينَ، قَالَ: وَكَانَ رَسُولُ اللهِ ﷺ إِذَا أَغَارَ فِي أَرْضِ الْعَدُوِّ، نَفَلَ الرُّبُعَ، وَإِذَا أَقْبَلَ رَاجِعاً وَكُلَّ النَّاسِ نَفَلَ الثُّلُثَ، وَكَانَ يَكْرَهُ الْأَنْفَالَ وَيَقُولُ: لِيَرُدَّ قَوِيُّ الْمُؤْمِنِينَ عَلَى ضَعِيفِهِمْ السَّوَاءِ. واللفظ لأحمد.\n\nوله شاهد من حديث جاء عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما.","id":""}],"4":[{"ar":"عَنْ سَعْدٍ رضي الله عنه: أَنَّهُ نَزَلَتْ فِيهِ آيَاتٌ مِنْ الْقُرْآنِ، قَالَ: حَلَفَتْ أُمُّ سَعْدٍ أَنْ لَا تُكَلِّمَهُ أَبَداً حَتَّى يَكْفُرَ بِدِينِهِ، وَلَا تَأْكُلَ وَلَا تَشْرَبَ، قَالَتْ: زَعَمْتَ أَنَّ اللهَ وَصَّاكَ بِوَالِدَيْكَ، وَأَنَا أُمُّكَ وَأَنَا آمُرُكَ بِهَذَا. قَالَ: مَكَثَتْ ثَلاثاً حَتَّى غُشِيَ عَلَيْهَا مِنْ الْجَهْدِ، فَقَامَ ابْنٌ لَهَا يُقَالُ لَهُ عُمَارَة، فَسَقَاهَا، فَجَعَلَتْ تَدْعُو عَلَى سَعْدٍ، فَأَنْزَلَ اللهُ عز و جل فِي الْقُرْآنِ هَذِهِ الْآيَةَ: { وَوَصَّيْنَا ٱلْإِنسَـٰنَ بِوَٰلِدَيْهِ حُسْنًا ۖ وَإِن جَـٰهَدَاكَ لِتُشْرِكَ بِى } وفيها { وَصَاحِبْهُمَا فِى ٱلدُّنْيَا مَعْرُوفًا ۖ }.\n\nقَالَ: وَأَصَابَ رَسُولُ اللهِ ﷺ غَنِيمَةً عَظِيمَةً، فَإِذَا فِيهَا سَيْفٌ فَأَخَذْتُهُ، فَأَتَيْتُ بِهِ الرَّسُولَ ﷺ، فَقُلْتُ: نَفِّلْنِي هَذَا السَّيْفَ، فَأَنَا مَنْ قَدْ عَلِمْتَ حَالَهُ. فَقَالَ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، فَانْطَلَقْتُ، حَتَّى إِذَا أَرَدْتُ أَنْ أُلْقِيَهُ فِي الْقَبْضِ لَامَتْنِي نَفْسِي، فَرَجَعْتُ إِلَيْهِ، فَقُلْتُ: أَعْطِنِيهِ، قَالَ: فَشَدَّ لِي صَوْتَهُ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، قَالَ: فَأَنْزَلَ اللهُ عز و جل: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ }. قَالَ: وَمَرِضْتُ فَأَرْسَلْتُ إِلَى النَّبِيِّ ﷺ فَأَتَانِي، فَقُلْتُ: دَعْنِي أَقْسِمْ مَالِي حَيْثُ شِئْتُ، قَالَ: فَأَبَى، قُلْتُ: فَالنِّصْفَ، قَالَ: فَأَبَى، قُلْتُ: فَالثُّلُثَ، قَالَ: فَسَكَتَ، فَكَانَ بَعْدُ، الثُّلُثُ جَائِزاً.\n\nقَالَ: وَأَتَيْتُ عَلَى نَفَرٍ مِنْ الْأَنْصَارِ وَالمُهَاجِرِينَ، فَقَالُوا: تَعَالَ نُطْعِمْكَ\nوَنَسْقِكَ خَمْراً، وَذَلِكَ قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ، قَالَ: فَأَتَيْتُهُمْ فِي حَشٍّ - وَالْحَشُّ الْبُسْتَانُ - فَإِذَا رَأْسُ جَزُورٍ مَشْوِيٌّ عِنْدَهُمْ، وَزِقٌ مِنْ خَمْرٍ، قَالَ: فَأَكَلْتُ وَشَرِبْتُ مَعَهُمْ، قَالَ: فَذَكَرْتُ الْأَنْصَارَ وَالْمُهَاجِرِينَ عِنْدَهُمْ، فَقُلْتُ: الْمُهَاجِرُونَ خَيْرٌ مِنْ الْأَنْصَارِ، قَالَ: فَأَخَذَ رَجُلٌ أَحَدَ لَحْيَيْ الرَّأْسِ فَضَرَبَنِي بِهِ فَجَرَحَ بِأَنْفِي، فَأَتَيْتُ رَسُولَ اللهِ ﷺ فَأَخْبَرْتُهُ، فَأَنْزَلَ اللهُ عز و جل فِيَّ - يَعْنِي نَفْسَهُ - شَأْنَ الْخَمْرِ: { إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ }. واللفظ لمسلم في الفضائل.","id":""},{"ar":"وللآية سبب آخر فقد جاء: عَنْ أَبِي أُمَامَةَ، عَنْ عُبَادَةَ بْنِ الصَّامِتِ رضي الله عنه قَالَ: خَرَجْنَا مَعَ النَّبِيِّ ﷺ فَشَهِدْتُ مَعَهُ بَدْراً، فَالْتَقَى النَّاسُ فَهَزَمَ اللهُ تَبَارَكَ وَتَعَالَى الْعَدُوَّ، فَانْطَلَقَتْ طَائِفَةٌ فِي آثَارِهِمْ يَهْزِمُونَ وَيَقْتُلُونَ، فَأَكَبَّتْ طَائِفَةٌ عَلَى الْعَسْكَرِ يَحْوُونَهُ وَيَجْمَعُونَهُ، وَأَحْدَقَتْ طَائِفَةٌ بِرَسُولِ اللهِ ﷺ لَا يُصِيبُ الْعَدُوُّ مِنْهُ غِرَّةً، حَتَّى إِذَا كَانَ اللَّيْلُ، وَفَاءَ النَّاسُ بَعْضُهُمْ إِلَى بَعْضٍ، قَالَ الَّذِينَ جَمَعُوا الْغَنَائِمَ: نَحْنُ حَوَيْنَاهَا وَجَمَعْنَاهَا، فَلَيْسَ لِأَحَدٍ فِيهَا نَصِيبٌ، وَقَالَ الَّذِينَ خَرَجُوا فِي طَلَبِ الْعَدُوِّ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا، نَحْنُ نَفَيْنَا عَنْهَا الْعَدُوَّ وَهَزَمْنَاهُمْ، وَقَالَ الَّذِينَ أَحْدَقُوا بِرَسُولِ اللهِ ﷺ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا نَحْنُ أَحْدَقْنَا بِرَسُولِ اللهِ ﷺ وَخِفْنَا أَنْ يُصِيبَ الْعَدُوُّ مِنْهُ غِرَّةً، وَاشْتَغَلْنَا بِهِ.\n\nفَنَزَلَتْ: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ قُلِ ٱلْأَنفَالُ لِلَّهِ وَٱلرَّسُولِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَصْلِحُوا۟ ذَاتَ بَيْنِكُمْ ۖ } فَقَسَمَهَا رَسُولُ الله ﷺ عَلَى فَوَاقٍ بَيْنَ الْمُسْلِمِينَ، قَالَ: وَكَانَ رَسُولُ اللهِ ﷺ إِذَا أَغَارَ فِي أَرْضِ الْعَدُوِّ، نَفَلَ الرُّبُعَ، وَإِذَا أَقْبَلَ رَاجِعاً وَكُلَّ النَّاسِ نَفَلَ الثُّلُثَ، وَكَانَ يَكْرَهُ الْأَنْفَالَ وَيَقُولُ: لِيَرُدَّ قَوِيُّ الْمُؤْمِنِينَ عَلَى ضَعِيفِهِمْ السَّوَاءِ. واللفظ لأحمد.\n\nوله شاهد من حديث جاء عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما.","id":""}],"5":[{"ar":"عَنْ سَعْدٍ رضي الله عنه: أَنَّهُ نَزَلَتْ فِيهِ آيَاتٌ مِنْ الْقُرْآنِ، قَالَ: حَلَفَتْ أُمُّ سَعْدٍ أَنْ لَا تُكَلِّمَهُ أَبَداً حَتَّى يَكْفُرَ بِدِينِهِ، وَلَا تَأْكُلَ وَلَا تَشْرَبَ، قَالَتْ: زَعَمْتَ أَنَّ اللهَ وَصَّاكَ بِوَالِدَيْكَ، وَأَنَا أُمُّكَ وَأَنَا آمُرُكَ بِهَذَا. قَالَ: مَكَثَتْ ثَلاثاً حَتَّى غُشِيَ عَلَيْهَا مِنْ الْجَهْدِ، فَقَامَ ابْنٌ لَهَا يُقَالُ لَهُ عُمَارَة، فَسَقَاهَا، فَجَعَلَتْ تَدْعُو عَلَى سَعْدٍ، فَأَنْزَلَ اللهُ عز و جل فِي الْقُرْآنِ هَذِهِ الْآيَةَ: { وَوَصَّيْنَا ٱلْإِنسَـٰنَ بِوَٰلِدَيْهِ حُسْنًا ۖ وَإِن جَـٰهَدَاكَ لِتُشْرِكَ بِى } وفيها { وَصَاحِبْهُمَا فِى ٱلدُّنْيَا مَعْرُوفًا ۖ }.\n\nقَالَ: وَأَصَابَ رَسُولُ اللهِ ﷺ غَنِيمَةً عَظِيمَةً، فَإِذَا فِيهَا سَيْفٌ فَأَخَذْتُهُ، فَأَتَيْتُ بِهِ الرَّسُولَ ﷺ، فَقُلْتُ: نَفِّلْنِي هَذَا السَّيْفَ، فَأَنَا مَنْ قَدْ عَلِمْتَ حَالَهُ. فَقَالَ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، فَانْطَلَقْتُ، حَتَّى إِذَا أَرَدْتُ أَنْ أُلْقِيَهُ فِي الْقَبْضِ لَامَتْنِي نَفْسِي، فَرَجَعْتُ إِلَيْهِ، فَقُلْتُ: أَعْطِنِيهِ، قَالَ: فَشَدَّ لِي صَوْتَهُ: « رُدُّهُ مِنْ حَيْثُ أَخَذْتَهُ »، قَالَ: فَأَنْزَلَ اللهُ عز و جل: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ }. قَالَ: وَمَرِضْتُ فَأَرْسَلْتُ إِلَى النَّبِيِّ ﷺ فَأَتَانِي، فَقُلْتُ: دَعْنِي أَقْسِمْ مَالِي حَيْثُ شِئْتُ، قَالَ: فَأَبَى، قُلْتُ: فَالنِّصْفَ، قَالَ: فَأَبَى، قُلْتُ: فَالثُّلُثَ، قَالَ: فَسَكَتَ، فَكَانَ بَعْدُ، الثُّلُثُ جَائِزاً.\n\nقَالَ: وَأَتَيْتُ عَلَى نَفَرٍ مِنْ الْأَنْصَارِ وَالمُهَاجِرِينَ، فَقَالُوا: تَعَالَ نُطْعِمْكَ\nوَنَسْقِكَ خَمْراً، وَذَلِكَ قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ، قَالَ: فَأَتَيْتُهُمْ فِي حَشٍّ - وَالْحَشُّ الْبُسْتَانُ - فَإِذَا رَأْسُ جَزُورٍ مَشْوِيٌّ عِنْدَهُمْ، وَزِقٌ مِنْ خَمْرٍ، قَالَ: فَأَكَلْتُ وَشَرِبْتُ مَعَهُمْ، قَالَ: فَذَكَرْتُ الْأَنْصَارَ وَالْمُهَاجِرِينَ عِنْدَهُمْ، فَقُلْتُ: الْمُهَاجِرُونَ خَيْرٌ مِنْ الْأَنْصَارِ، قَالَ: فَأَخَذَ رَجُلٌ أَحَدَ لَحْيَيْ الرَّأْسِ فَضَرَبَنِي بِهِ فَجَرَحَ بِأَنْفِي، فَأَتَيْتُ رَسُولَ اللهِ ﷺ فَأَخْبَرْتُهُ، فَأَنْزَلَ اللهُ عز و جل فِيَّ - يَعْنِي نَفْسَهُ - شَأْنَ الْخَمْرِ: { إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ }. واللفظ لمسلم في الفضائل.","id":""},{"ar":"وللآية سبب آخر فقد جاء: عَنْ أَبِي أُمَامَةَ، عَنْ عُبَادَةَ بْنِ الصَّامِتِ رضي الله عنه قَالَ: خَرَجْنَا مَعَ النَّبِيِّ ﷺ فَشَهِدْتُ مَعَهُ بَدْراً، فَالْتَقَى النَّاسُ فَهَزَمَ اللهُ تَبَارَكَ وَتَعَالَى الْعَدُوَّ، فَانْطَلَقَتْ طَائِفَةٌ فِي آثَارِهِمْ يَهْزِمُونَ وَيَقْتُلُونَ، فَأَكَبَّتْ طَائِفَةٌ عَلَى الْعَسْكَرِ يَحْوُونَهُ وَيَجْمَعُونَهُ، وَأَحْدَقَتْ طَائِفَةٌ بِرَسُولِ اللهِ ﷺ لَا يُصِيبُ الْعَدُوُّ مِنْهُ غِرَّةً، حَتَّى إِذَا كَانَ اللَّيْلُ، وَفَاءَ النَّاسُ بَعْضُهُمْ إِلَى بَعْضٍ، قَالَ الَّذِينَ جَمَعُوا الْغَنَائِمَ: نَحْنُ حَوَيْنَاهَا وَجَمَعْنَاهَا، فَلَيْسَ لِأَحَدٍ فِيهَا نَصِيبٌ، وَقَالَ الَّذِينَ خَرَجُوا فِي طَلَبِ الْعَدُوِّ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا، نَحْنُ نَفَيْنَا عَنْهَا الْعَدُوَّ وَهَزَمْنَاهُمْ، وَقَالَ الَّذِينَ أَحْدَقُوا بِرَسُولِ اللهِ ﷺ: لَسْتُمْ بِأَحَقَّ بِهَا مِنَّا نَحْنُ أَحْدَقْنَا بِرَسُولِ اللهِ ﷺ وَخِفْنَا أَنْ يُصِيبَ الْعَدُوُّ مِنْهُ غِرَّةً، وَاشْتَغَلْنَا بِهِ.\n\nفَنَزَلَتْ: { يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ قُلِ ٱلْأَنفَالُ لِلَّهِ وَٱلرَّسُولِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَصْلِحُوا۟ ذَاتَ بَيْنِكُمْ ۖ } فَقَسَمَهَا رَسُولُ الله ﷺ عَلَى فَوَاقٍ بَيْنَ الْمُسْلِمِينَ، قَالَ: وَكَانَ رَسُولُ اللهِ ﷺ إِذَا أَغَارَ فِي أَرْضِ الْعَدُوِّ، نَفَلَ الرُّبُعَ، وَإِذَا أَقْبَلَ رَاجِعاً وَكُلَّ النَّاسِ نَفَلَ الثُّلُثَ، وَكَانَ يَكْرَهُ الْأَنْفَالَ وَيَقُولُ: لِيَرُدَّ قَوِيُّ الْمُؤْمِنِينَ عَلَى ضَعِيفِهِمْ السَّوَاءِ. واللفظ لأحمد.\n\nوله شاهد من حديث جاء عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما.","id":""},{"ar":"وعن أبي أيوب الأنصاري رضي الله عنه قال: قال رسول الله ﷺ: ونحن بالمدينة: « إني أخبرت ونحن بالمدينة عن عير أبي سفيان أنها مقبلة، فهل لكم أن نخرج قبل هذا العير، لعل الله يغنمناها »، قلنا: نعم، فخرج و خرجنا معه، فلما سرنا يوماً أو يومين، قال لنا: « ما ترون في القوم فإنهم أخبروا بمخرجكم؟ » فقلنا: لا والله ما لنا طاقة بقتال العدو، ولكن أردنا العير، ثم قال: « ما ترون في القوم؟ » فقلنا: مثل ذلك، فقال المقداد بن عمرو: إذاً لا نقول لك يا رسول الله كما قال قوم موسى لموسى: \"اذهب أنت وربك فقاتلا إنا ههنا قاعدون\". قال: فتمنينا معشر الأنصار أنا قلنا كما قال المقداد، أحب إلينا من أن يكون لنا مال عظيم، فأنزل الله عز و جل على رسوله ﷺ { كَمَآ أَخْرَجَكَ رَبُّكَ مِنۢ بَيْتِكَ بِٱلْحَقِّ وَإِنَّ فَرِيقًا مِّنَ ٱلْمُؤْمِنِينَ لَكَـٰرِهُونَ ﴿٥﴾ يُجَـٰدِلُونَكَ فِى ٱلْحَقِّ بَعْدَ مَا تَبَيَّنَ كَأَنَّمَا يُسَاقُونَ إِلَى ٱلْمَوْتِ وَهُمْ يَنظُرُونَ ﴿٦﴾ }.","id":""}],"9":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما: حَدَّثَنِي عُمَرُ بْنُ الْخَطَّابَ رضي الله عنه قَالَ: لَمَّا كَانَ يَوْمُ بَدْرٍ، نَظَرَ النَّبِيُّ ﷺ إِلَى أَصْحَابِهِ وَهُمْ ثَلَاثُ مِئَةٍ وَنَيْفٌ، وَنَظَرَ إِلَى الْمُشْرِكِينَ وَهُمْ أَلْفٌ وَزِيَادَةٌ، فَاسْتَقْبَلَ النَّبِيُّ ﷺ الْقِبْلَةَ ثُمَّ مَدَّ يَدَيْهِ، وَعَلَيْهِ رِدَاؤُهُ وَإِزَارُهُ، ثُمَّ قَالَ: « اللَّهُمَّ أَيْنَ مَا وَعَدْتَنِي؟، اللَّهُمَّ أَنجزْ لِي مَا وَعَدْتَنِي، اللَّهُمَّ إِنْ تَهْلِكُ هَذِهِ الْعِصَابَةُ مِنْ أَهْلِ الْإِسْلَام فَلَا تُعْبَدْ فِي الْأَرْضِ أَبداً »، قَالَ: فَمَا زَالَ يَسْتَغِيثُ رَبَّهُ عز و جل، وَيَدْعُوهُ حَتَّى سَقَطَ رِدَاؤُهُ عَنْ مَنْكِبَيْهِ، فَأَتَاهُ أَبُو بَكْرٍ، فَأَخَذَ رِدَاءَهُ فَرَدَّاهُ ثُمَّ الْتَزَمَهُ مِنْ وَرَائِهِ، ثُمَّ قَالَ: يَا نَبِيَّ اللهِ كَفَاكَ مُنَاشَدَتُكَ رَبَّكَ، فَإِنَّهُ سَيُنْجِزُ لَكَ مَا وَعَدَكَ، فَأَنْزَلَ اللهُ عز و جل { إِذْ تَسْتَغِيثُونَ رَبَّكُمْ فَٱسْتَجَابَ لَكُمْ أَنِّى مُمِدُّكُم بِأَلْفٍ مِّنَ ٱلْمَلَـٰٓئِكَةِ مُرْدِفِينَ ﴿٩﴾... } واللفظ لأحمد.","id":""}],"17":[{"ar":"وعن حكيم بن حزام رضي الله عنه قال: لما كان يوم بدر، أمر رسول الله ﷺ علياً فأخذ كفَّا من الحصى، فاستقبلنا به، فرمى بها، وقال: « شاهت الوجوه »، فانهزمنا فأنزل الله عز و جل: { وَمَا رَمَيْتَ إِذْ رَمَيْتَ وَلَـٰكِنَّ ٱللَّهَ رَمَىٰ ۚ }.","id":""},{"ar":"وعن ابن عباس رضي الله عنهما: أن النبي ﷺ قال لعلي: « ناولني كفا من حصی »، فناوله، فرمی به وجوه القوم، فما بقي أحد من القوم إلا امتلأت عيناه من الحصباء، فنزلت: { وَمَا رَمَيْتَ إِذْ رَمَيْتَ وَلَـٰكِنَّ ٱللَّهَ رَمَىٰ ۚ }، الآية.","id":""}],"19":[{"ar":"عن عبد الله بن ثعلبة بن صُعَيْر رضي الله عنه: أن أبا جهل قال يوم بدر: اللهم أينا كان أقطع للرحم، وآتانا بما لا يعرف، فأحنه الغداة، وكان استفتاحاً منه، فنزلت: { إِن تَسْتَفْتِحُوا۟ فَقَدْ جَآءَكُمُ ٱلْفَتْحُ ۖ }، إلى آخر الآية.","id":""}],"33":[{"ar":"عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه: قَالَ أَبُو جَهْلٍ: اللَّهُمَّ إِنْ كَانَ هَذَا هُوَ الْحَقَّ مِنْ عِنْدِكَ فَأَمْطِرْ عَلَيْنَا حِجَارَةً مِنْ السَّمَاءِ أَوْ ائْتِنَا بِعَذَابٍ أَلِيمٍ، فَنَزَلَتْ: { وَمَا كَانَ ٱللَّهُ لِيُعَذِّبَهُمْ وَأَنتَ فِيهِمْ ۚ وَمَا كَانَ ٱللَّهُ مُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَ ﴿٣٣﴾ } الْآيَةَ.","id":""}],"34":[{"ar":"عَنْ أَنَسِ بْنِ مَالِكٍ رضي الله عنه: قَالَ أَبُو جَهْلٍ: اللَّهُمَّ إِنْ كَانَ هَذَا هُوَ الْحَقَّ مِنْ عِنْدِكَ فَأَمْطِرْ عَلَيْنَا حِجَارَةً مِنْ السَّمَاءِ أَوْ ائْتِنَا بِعَذَابٍ أَلِيمٍ، فَنَزَلَتْ: { وَمَا كَانَ ٱللَّهُ لِيُعَذِّبَهُمْ وَأَنتَ فِيهِمْ ۚ وَمَا كَانَ ٱللَّهُ مُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَ ﴿٣٣﴾ } الْآيَةَ.","id":""}],"67":[{"ar":"عن ابنِ عَبَّاسٍ قَالَ: بَيْنَمَا رَجُلٌ مِنْ الْمُسْلِمِينَ يَوْمَئِذٍ يَشْتَدُّ فِي أَثَرِ رَجُلٍ مِنْ الْمُشْرِكِينَ أَمَامَهُ، إِذْ سَمِعَ ضَرْبَةً بِالسَّوْطِ فَوْقَهُ، وَصَوْتَ الْفَارِسِ يَقُولُ: أَقْدِمْ حَيْزُومُ، فَنَظَرَ إِلَى الْمُشْرِكِ أَمَامَهُ فَخَرَّ مُسْتَلْقِياً، فَنَظَرَ إِلَيْهِ فَإِذَا هُوَ قَدْ خُطِمَ أَنْفُهُ، وَشُقَّ وَجْهُهُ كَضَرْبَةِ السَّوْطِ، فَاخْضَرَّ ذَلِكَ أَجْمَعُ، فَجَاءَ الْأَنْصَارِيُّ فَحَدَّثَ بِذَلِكَ رَسُولَ اللهِ ﷺ فَقَالَ: « صَدَقْتَ، ذَلِكَ مِنْ مَدَدِ السَّمَاءِ الثَّالِثَةِ » فَقَتَلُوا يَوْمَئِذٍ سَبْعِينَ، وَأَسَرُوا سَبْعِينَ.\n\nقَالَ أَبُو زُمَيْلٍ: قَالَ ابْنُ عَبَّاسٍ: فَلَمَّا أَسَرُوا الْأَسَارَى، قَالَ رَسُولُ اللهِ ﷺ لِأَبِي بَكْرٍ وَعُمَرَ: « مَا تَرَوْنَ فِي هَؤُلَاءِ الْأُسَارَى؟ »، فَقَالَ أَبُو بَكْرٍ: يَا نَبِيَّ اللهِ! هُمْ بَنُو الْعَمِّ وَالْعَشِيرَةِ، أَرَى أَنْ تَأْخُذَ مِنْهُمْ فِدْيَةٍ، فَتَكُونُ لَنَا قُوَّةً عَلَى الْكُفَّارِ، فَعَسَى اللهُ أَنْ يَهْدِيَهُمْ لِلْإِسْلَامِ. فَقَالَ رَسُولُ اللهِ ﷺ: « مَا تَرَى يَا ابْنَ الْخَطَابِ؟ » قُلْتُ: لَا، وَاللهِ يَا رَسُولَ اللهِ، مَا أَرَى الَّذِي رَأَى أَبُو بَكْرٍ، وَلَكِنِّي أَرَى أَنْ تُمَكّنَّا فَنَضْرِبَ أَعْنَاقُهُمْ، فَتُمَكِّنَ عَلِيًّا مِنْ عَقِيلٍ فَيَضْرِبَ عُنُقَهُ، وَتُمَكَّنِّي مِنْ - فُلَانٍ نَسِيباً لِعُمَرَ - فَأَضْرِبَ عُنُقَهُ، فَإِنَّ هَؤُلَاءِ أَئِمَّةُ الْكُفْرِ وَصَنَادِيدُهَا، فَهَوِيَ رَسُولُ اللهِ ﷺ مَا قَالَ أَبُو بَكْرٍ، وَلَمْ يَهْوَ مَا قُلْتُ.\n\nفَلَمَّا كَانَ مِنْ الْغَدِ جِئْتُ فَإِذَا رَسُولُ اللهِ ﷺ وَأَبُو بَكْر قَاعِدَيْ��ِ يَبْكِيَان، قُلْتُ: يَا رَسُولَ اللهِ، أَخْبِرْنِي مِنْ أَيِّ شَيْءٍ تَبْكي أَنْتَ وَصَاحِبُكَ، فَإِنْ وَجَدْتُ بُكَاءً بَكَيْتُ، وَإِنْ لَمْ أَجِدُ بُكَاءً تَبَاكَيْتُ لِبُكَائِكُمَا، فَقَالَ رَسُولُ اللهِ ﷺ: « أَبْكِي لِلَّذِي عَرَضَ عَلَيَّ أَصْحَابُكَ مِنْ أَخْذِهِم الْفِدَاءَ، لَقَدْ عُرِضَ عَلَيَّ عَذَابُهُمْ أَدْنَى مِنْ هَذِهِ الشَّجَرَةِ » - شَجَرَةٍ قَرِيبَةٍ مِنْ نَبِيِّ اللهِ ﷺ - وَأَنْزَلَ اللهُ عز و جل: { مَا كَانَ لِنَبِىٍّ أَن يَكُونَ لَهُۥٓ أَسْرَىٰ حَتَّىٰ يُثْخِنَ فِى ٱلْأَرْضِ ۚ } إِلَى قَوْلِهِ { فَكُلُوا۟ مِمَّا غَنِمْتُمْ حَلَـٰلًا طَيِّبًا ۚ } فَأَحَلَّ اللهُ الْغَنِيمَةَ لَهُمْ. واللفظ لمسلم.","id":""},{"ar":"عَنْ عَبْدِ اللهِ - يَعْنِي ابْنَ مَسْعُودٍ رضي الله عنه - قَالَ: لَمَّا كَانَ يَوْمُ بَدْرٍ، قَالَ: قَالَ رَسُولُ اللهِ ﷺ: « مَا تَقُولُونَ فِي هَؤُلَاءِ الْأَسْرَى؟ » قَالَ: فَقَالَ أَبُو بَكْرٍ: يَا رَسُولَ اللهِ، قَوْمُكَ وَأَهْلُكَ، اسْتَبْقِهِمْ، وَاسْتَأْنِ بِهِمْ، لَعَلَّ اللهَ أَنْ يَتُوبَ عَلَيْهِمْ، قَالَ: وَقَالَ عُمَرُ: يَا رَسُولَ اللهِ، أَخْرَجُوكَ وَكَذَّبُوكَ، قَرِّبْهُمْ فَاضْرِبْ أَعْنَاقَهُمْ، قَالَ: وَقَالَ عَبْدُ اللهِ بْنُ رَوَاحَةَ: يَا رَسُولَ اللهِ، انْظُرْ وَادِياً كَثِيرَ الْحَطَبِ، فَأَدْخِلْهُمْ فِيهِ، ثُمَّ أَضْرِمْ عَلَيْهِمْ نَاراً، قَالَ: فَقَالَ الْعَبَّاسُ: قَطَعْتَ رَحِمَكَ، قَالَ: فَدَخَلَ رَسُولُ اللهِ ﷺ، وَلَمْ يَرُدَّ عَلَيْهِمْ شَيْئًا، قَالَ: فَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ أَبِي بَكْرٍ، وَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ عُمَرَ، وَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ عَبْدِ اللهِ بْنِ رَوَاحَةَ، قَالَ: فَخَرَجَ عَلَيْهِمْ رَسُولُ اللهِ ﷺ، فَقَالَ: « إِنَّ الله لَيُلِينُ قُلُوبَ رِجَالٍ فِيهِ، حَتَّى تَكُونَ أَلْيَنَ مِنْ اللَّبَنِ، وَإِنَّ اللهَ لَيَشُدُّ قُلُوبَ رِجَالٍ فِيهِ، حَتَّى تَكُونَ أَشَدَّ مِنْ الْحِجَارَةِ، وَإِنَّ مَثَلَكَ يَا أَبَا بَكْرٍ، كَمَثَلِ إِبْرَاهِيمَ عليه السلام قَالَ: { فَمَن تَبِعَنِى فَإِنَّهُۥ مِنِّى ۖ وَمَنْ عَصَانِى فَإِنَّكَ غَفُورٌ رَّحِيمٌ }، وَمَثَلَكَ يَا أَبَا بَكْرٍ، كَمَثَل عِيسَى، قَالَ: { إِن تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ ۖ وَإِن تَغْفِرْ لَهُمْ فَإِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ ﴿١١٨﴾ }، وَإِنْ مَثَلَكَ يَا عُمَرُ، كَمَثَلِ نُوحٍ، قَالَ: { رَّبِّ لَا تَذَرْ عَلَى ٱلْأَرْضِ مِنَ ٱلْكَـٰفِرِينَ دَيَّارًا }، وَإِنَّ مِثْلَكَ يَا عُمَرُ، كَمَثَلِ مُوسَى، قَالَ: { وَٱشْدُدْ عَلَىٰ قُلُوبِهِمْ فَلَا يُؤْمِنُوا۟ حَتَّىٰ يَرَوُا۟ ٱلْعَذَابَ ٱلْأَلِيمَ }، أَنْتُمْ عَالَةٌ فَلَا يَنْفَلِئَنَّ مِنْهُمْ أَحَدٌ إِلَّا بِفِدَاءٍ، أَوْ ضَرْبَةِ عُنُقٍ »، قَالَ عَبْدُ الله: فَقُلْتُ: يَا رَسُولَ اللهِ، إِلَّا سُهَيْلُ ابْنُ بَيْضَاءَ، فَإِنِّي قَدْ سَمِعْتُهُ يَذْكُرُ الْإِسْلَامَ، قَالَ: فَسَكَتَ، قَالَ: فَمَا رَأَيْتُنِي فِي يَوْمٍ، أَخْوَفَ أَنْ تَقَعَ عَلَيَّ حِجَارَةٌ مِنْ السَّمَاءِ، فِي ذَلِكَ الْيَوْمِ حَتَّى قَالَ: « إِلَّا سُهَيْلُ ابْنُ بَيْضَاءَ »، قَالَ: فَأَنْزَلَ اللهُ عز و جل { مَا كَانَ لِنَبِىٍّ أَن يَكُونَ لَهُۥٓ أَسْرَىٰ حَتَّىٰ يُثْخِنَ فِى ٱلْأَرْضِ ۚ تُرِيدُونَ عَرَضَ ٱلدُّنْيَا وَٱللَّهُ يُرِيدُ ٱلْـَٔاخِرَةَ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ ﴿٦٧﴾ } إِلَى قَوْلِهِ { لَّوْلَا كِتَٰبٌ مِّنَ ٱللَّهِ سَبَقَ لَمَسَّكُمْ فِيمَآ أَخَذْتُمْ عَذَابٌ عَظِيمٌ ﴿٦٨﴾ }. واللفظ لأحمد.\n\nوقد جاء عن ابن عمر عن النبي ﷺ شبيهاً به.\n\nوقد جاء عَنْ أَنَسٍ له شبيهاً بما جاء عن ابن عباس.","id":""}],"68":[{"ar":"عن ابنِ عَبَّاسٍ قَالَ: بَيْنَمَا رَجُلٌ مِنْ الْمُسْلِمِينَ يَوْمَئِذٍ يَشْتَدُّ فِي أَثَرِ رَجُلٍ مِنْ الْمُشْرِكِينَ أَمَامَهُ، إِذْ سَمِعَ ضَرْبَةً بِالسَّوْطِ فَوْقَهُ، وَصَوْتَ الْفَارِسِ يَقُولُ: أَقْدِمْ حَيْزُومُ، فَنَظَرَ إِلَى الْمُشْرِكِ أَمَامَهُ فَخَرَّ مُسْتَلْقِياً، فَنَظَرَ إِلَيْهِ فَإِذَا هُوَ قَدْ خُطِمَ أَنْفُهُ، وَشُقَّ وَجْهُهُ كَضَرْبَةِ السَّوْطِ، فَاخْضَرَّ ذَلِكَ أَجْمَعُ، فَجَاءَ الْأَنْصَارِيُّ فَحَدَّثَ بِذَلِكَ رَسُولَ اللهِ ﷺ فَقَالَ: « صَدَقْتَ، ذَلِكَ مِنْ مَدَدِ السَّمَاءِ الثَّالِثَةِ » فَقَتَلُوا يَوْمَئِذٍ سَبْعِينَ، وَأَسَرُوا سَبْعِينَ.\n\nقَالَ أَبُو زُمَيْلٍ: قَالَ ابْنُ عَبَّاسٍ: فَلَمَّا أَسَرُوا الْأَسَارَى، قَالَ رَسُولُ اللهِ ﷺ لِأَبِي بَكْرٍ وَعُمَرَ: « مَا تَرَوْنَ فِي هَؤُلَاءِ الْأُسَارَى؟ »، فَقَالَ أَبُو بَكْرٍ: يَا نَبِيَّ اللهِ! هُمْ بَنُو الْعَمِّ وَالْعَشِيرَةِ، أَرَى أَنْ تَأْخُذَ مِنْهُمْ فِدْيَةٍ، فَتَكُونُ لَنَا قُوَّةً عَلَى الْكُفَّارِ، فَعَسَى اللهُ أَنْ يَهْدِيَهُمْ لِلْإِسْلَامِ. فَقَالَ رَسُولُ اللهِ ﷺ: « مَا تَرَى يَا ابْنَ الْخَطَابِ؟ » قُلْتُ: لَا، وَاللهِ يَا رَسُولَ اللهِ، مَا أَرَى الَّذِي رَأَى أَبُو بَكْرٍ، وَلَكِنِّي أَرَى أَنْ تُمَكّنَّا فَنَضْرِبَ أَعْنَاقُهُمْ، فَتُمَكِّنَ عَلِيًّا مِنْ عَقِيلٍ فَيَضْرِبَ عُنُقَهُ، وَتُمَكَّنِّي مِنْ - فُلَانٍ نَسِيباً لِعُمَرَ - فَأَضْرِبَ عُنُقَهُ، فَإِنَّ هَؤُلَاءِ أَئِمَّةُ الْكُفْرِ وَصَنَادِيدُهَا، فَهَوِيَ رَسُولُ اللهِ ﷺ مَا قَالَ أَبُو بَكْرٍ، وَلَمْ يَهْوَ مَا قُلْتُ.\n\nفَلَمَّا كَانَ مِنْ الْغَدِ جِئْتُ فَإِذَا رَسُولُ اللهِ ﷺ وَأَبُو بَكْر قَاعِدَيْ��ِ يَبْكِيَان، قُلْتُ: يَا رَسُولَ اللهِ، أَخْبِرْنِي مِنْ أَيِّ شَيْءٍ تَبْكي أَنْتَ وَصَاحِبُكَ، فَإِنْ وَجَدْتُ بُكَاءً بَكَيْتُ، وَإِنْ لَمْ أَجِدُ بُكَاءً تَبَاكَيْتُ لِبُكَائِكُمَا، فَقَالَ رَسُولُ اللهِ ﷺ: « أَبْكِي لِلَّذِي عَرَضَ عَلَيَّ أَصْحَابُكَ مِنْ أَخْذِهِم الْفِدَاءَ، لَقَدْ عُرِضَ عَلَيَّ عَذَابُهُمْ أَدْنَى مِنْ هَذِهِ الشَّجَرَةِ » - شَجَرَةٍ قَرِيبَةٍ مِنْ نَبِيِّ اللهِ ﷺ - وَأَنْزَلَ اللهُ عز و جل: { مَا كَانَ لِنَبِىٍّ أَن يَكُونَ لَهُۥٓ أَسْرَىٰ حَتَّىٰ يُثْخِنَ فِى ٱلْأَرْضِ ۚ } إِلَى قَوْلِهِ { فَكُلُوا۟ مِمَّا غَنِمْتُمْ حَلَـٰلًا طَيِّبًا ۚ } فَأَحَلَّ اللهُ الْغَنِيمَةَ لَهُمْ. واللفظ لمسلم.","id":""},{"ar":"عَنْ عَبْدِ اللهِ - يَعْنِي ابْنَ مَسْعُودٍ رضي الله عنه - قَالَ: لَمَّا كَانَ يَوْمُ بَدْرٍ، قَالَ: قَالَ رَسُولُ اللهِ ﷺ: « مَا تَقُولُونَ فِي هَؤُلَاءِ الْأَسْرَى؟ » قَالَ: فَقَالَ أَبُو بَكْرٍ: يَا رَسُولَ اللهِ، قَوْمُكَ وَأَهْلُكَ، اسْتَبْقِهِمْ، وَاسْتَأْنِ بِهِمْ، لَعَلَّ اللهَ أَنْ يَتُوبَ عَلَيْهِمْ، قَالَ: وَقَالَ عُمَرُ: يَا رَسُولَ اللهِ، أَخْرَجُوكَ وَكَذَّبُوكَ، قَرِّبْهُمْ فَاضْرِبْ أَعْنَاقَهُمْ، قَالَ: وَقَالَ عَبْدُ اللهِ بْنُ رَوَاحَةَ: يَا رَسُولَ اللهِ، انْظُرْ وَادِياً كَثِيرَ الْحَطَبِ، فَأَدْخِلْهُمْ فِيهِ، ثُمَّ أَضْرِمْ عَلَيْهِمْ نَاراً، قَالَ: فَقَالَ الْعَبَّاسُ: قَطَعْتَ رَحِمَكَ، قَالَ: فَدَخَلَ رَسُولُ اللهِ ﷺ، وَلَمْ يَرُدَّ عَلَيْهِمْ شَيْئًا، قَالَ: فَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ أَبِي بَكْرٍ، وَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ عُمَرَ، وَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ عَبْدِ اللهِ بْنِ رَوَاحَةَ، قَالَ: فَخَرَجَ عَلَيْهِمْ رَسُولُ اللهِ ﷺ، فَقَالَ: « إِنَّ الله لَيُلِينُ قُلُوبَ رِجَالٍ فِيهِ، حَتَّى تَكُونَ أَلْيَنَ مِنْ اللَّبَنِ، وَإِنَّ اللهَ لَيَشُدُّ قُلُوبَ رِجَالٍ فِيهِ، حَتَّى تَكُونَ أَشَدَّ مِنْ الْحِجَارَةِ، وَإِنَّ مَثَلَكَ يَا أَبَا بَكْرٍ، كَمَثَلِ إِبْرَاهِيمَ عليه السلام قَالَ: { فَمَن تَبِعَنِى فَإِنَّهُۥ مِنِّى ۖ وَمَنْ عَصَانِى فَإِنَّكَ غَفُورٌ رَّحِيمٌ }، وَمَثَلَكَ يَا أَبَا بَكْرٍ، كَمَثَل عِيسَى، قَالَ: { إِن تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ ۖ وَإِن تَغْفِرْ لَهُمْ فَإِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ ﴿١١٨﴾ }، وَإِنْ مَثَلَكَ يَا عُمَرُ، كَمَثَلِ نُوحٍ، قَالَ: { رَّبِّ لَا تَذَرْ عَلَى ٱلْأَرْضِ مِنَ ٱلْكَـٰفِرِينَ دَيَّارًا }، وَإِنَّ مِثْلَكَ يَا عُمَرُ، كَمَثَلِ مُوسَى، قَالَ: { وَٱشْدُدْ عَلَىٰ قُلُوبِهِمْ فَلَا يُؤْمِنُوا۟ حَتَّىٰ يَرَوُا۟ ٱلْعَذَابَ ٱلْأَلِيمَ }، أَنْتُمْ عَالَةٌ فَلَا يَنْفَلِئَنَّ مِنْهُمْ أَحَدٌ إِلَّا بِفِدَاءٍ، أَوْ ضَرْبَةِ عُنُقٍ »، قَالَ عَبْدُ الله: فَقُلْتُ: يَا رَسُولَ اللهِ، إِلَّا سُهَيْلُ ابْنُ بَيْضَاءَ، فَإِنِّي قَدْ سَمِعْتُهُ يَذْكُرُ الْإِسْلَامَ، قَالَ: فَسَكَتَ، قَالَ: فَمَا رَأَيْتُنِي فِي يَوْمٍ، أَخْوَفَ أَنْ تَقَعَ عَلَيَّ حِجَارَةٌ مِنْ السَّمَاءِ، فِي ذَلِكَ الْيَوْمِ حَتَّى قَالَ: « إِلَّا سُهَيْلُ ابْنُ بَيْضَاءَ »، قَالَ: فَأَنْزَلَ اللهُ عز و جل { مَا كَانَ لِنَبِىٍّ أَن يَكُونَ لَهُۥٓ أَسْرَىٰ حَتَّىٰ يُثْخِنَ فِى ٱلْأَرْضِ ۚ تُرِيدُونَ عَرَضَ ٱلدُّنْيَا وَٱللَّهُ يُرِيدُ ٱلْـَٔاخِرَةَ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ ﴿٦٧﴾ } إِلَى قَوْلِهِ { لَّوْلَا كِتَٰبٌ مِّنَ ٱللَّهِ سَبَقَ لَمَسَّكُمْ فِيمَآ أَخَذْتُمْ عَذَابٌ عَظِيمٌ ﴿٦٨﴾ }. واللفظ لأحمد.\n\nوقد جاء عن ابن عمر عن النبي ﷺ شبيهاً به.\n\nوقد جاء عَنْ أَنَسٍ له شبيهاً بما جاء عن ابن عباس.","id":""}],"69":[{"ar":"عن ابنِ عَبَّاسٍ قَالَ: بَيْنَمَا رَجُلٌ مِنْ الْمُسْلِمِينَ يَوْمَئِذٍ يَشْتَدُّ فِي أَثَرِ رَجُلٍ مِنْ الْمُشْرِكِينَ أَمَامَهُ، إِذْ سَمِعَ ضَرْبَةً بِالسَّوْطِ فَوْقَهُ، وَصَوْتَ الْفَارِسِ يَقُولُ: أَقْدِمْ حَيْزُومُ، فَنَظَرَ إِلَى الْمُشْرِكِ أَمَامَهُ فَخَرَّ مُسْتَلْقِياً، فَنَظَرَ إِلَيْهِ فَإِذَا هُوَ قَدْ خُطِمَ أَنْفُهُ، وَشُقَّ وَجْهُهُ كَضَرْبَةِ السَّوْطِ، فَاخْضَرَّ ذَلِكَ أَجْمَعُ، فَجَاءَ الْأَنْصَارِيُّ فَحَدَّثَ بِذَلِكَ رَسُولَ اللهِ ﷺ فَقَالَ: « صَدَقْتَ، ذَلِكَ مِنْ مَدَدِ السَّمَاءِ الثَّالِثَةِ » فَقَتَلُوا يَوْمَئِذٍ سَبْعِينَ، وَأَسَرُوا سَبْعِينَ.\n\nقَالَ أَبُو زُمَيْلٍ: قَالَ ابْنُ عَبَّاسٍ: فَلَمَّا أَسَرُوا الْأَسَارَى، قَالَ رَسُولُ اللهِ ﷺ لِأَبِي بَكْرٍ وَعُمَرَ: « مَا تَرَوْنَ فِي هَؤُلَاءِ الْأُسَارَى؟ »، فَقَالَ أَبُو بَكْرٍ: يَا نَبِيَّ اللهِ! هُمْ بَنُو الْعَمِّ وَالْعَشِيرَةِ، أَرَى أَنْ تَأْخُذَ مِنْهُمْ فِدْيَةٍ، فَتَكُونُ لَنَا قُوَّةً عَلَى الْكُفَّارِ، فَعَسَى اللهُ أَنْ يَهْدِيَهُمْ لِلْإِسْلَامِ. فَقَالَ رَسُولُ اللهِ ﷺ: « مَا تَرَى يَا ابْنَ الْخَطَابِ؟ » قُلْتُ: لَا، وَاللهِ يَا رَسُولَ اللهِ، مَا أَرَى الَّذِي رَأَى أَبُو بَكْرٍ، وَلَكِنِّي أَرَى أَنْ تُمَكّنَّا فَنَضْرِبَ أَعْنَاقُهُمْ، فَتُمَكِّنَ عَلِيًّا مِنْ عَقِيلٍ فَيَضْرِبَ عُنُقَهُ، وَتُمَكَّنِّي مِنْ - فُلَانٍ نَسِيباً لِعُمَرَ - فَأَضْرِبَ عُنُقَهُ، فَإِنَّ هَؤُلَاءِ أَئِمَّةُ الْكُفْرِ وَصَنَادِيدُهَا، فَهَوِيَ رَسُولُ اللهِ ﷺ مَا قَالَ أَبُو بَكْرٍ، وَلَمْ يَهْوَ مَا قُلْتُ.\n\nفَلَمَّا كَانَ مِنْ الْغَدِ جِئْتُ فَإِذَا رَسُولُ اللهِ ﷺ وَأَبُو بَكْر قَاعِدَيْ��ِ يَبْكِيَان، قُلْتُ: يَا رَسُولَ اللهِ، أَخْبِرْنِي مِنْ أَيِّ شَيْءٍ تَبْكي أَنْتَ وَصَاحِبُكَ، فَإِنْ وَجَدْتُ بُكَاءً بَكَيْتُ، وَإِنْ لَمْ أَجِدُ بُكَاءً تَبَاكَيْتُ لِبُكَائِكُمَا، فَقَالَ رَسُولُ اللهِ ﷺ: « أَبْكِي لِلَّذِي عَرَضَ عَلَيَّ أَصْحَابُكَ مِنْ أَخْذِهِم الْفِدَاءَ، لَقَدْ عُرِضَ عَلَيَّ عَذَابُهُمْ أَدْنَى مِنْ هَذِهِ الشَّجَرَةِ » - شَجَرَةٍ قَرِيبَةٍ مِنْ نَبِيِّ اللهِ ﷺ - وَأَنْزَلَ اللهُ عز و جل: { مَا كَانَ لِنَبِىٍّ أَن يَكُونَ لَهُۥٓ أَسْرَىٰ حَتَّىٰ يُثْخِنَ فِى ٱلْأَرْضِ ۚ } إِلَى قَوْلِهِ { فَكُلُوا۟ مِمَّا غَنِمْتُمْ حَلَـٰلًا طَيِّبًا ۚ } فَأَحَلَّ اللهُ الْغَنِيمَةَ لَهُمْ. واللفظ لمسلم.","id":""},{"ar":"عَنْ عَبْدِ اللهِ - يَعْنِي ابْنَ مَسْعُودٍ رضي الله عنه - قَالَ: لَمَّا كَانَ يَوْمُ بَدْرٍ، قَالَ: قَالَ رَسُولُ اللهِ ﷺ: « مَا تَقُولُونَ فِي هَؤُلَاءِ الْأَسْرَى؟ » قَالَ: فَقَالَ أَبُو بَكْرٍ: يَا رَسُولَ اللهِ، قَوْمُكَ وَأَهْلُكَ، اسْتَبْقِهِمْ، وَاسْتَأْنِ بِهِمْ، لَعَلَّ اللهَ أَنْ يَتُوبَ عَلَيْهِمْ، قَالَ: وَقَالَ عُمَرُ: يَا رَسُولَ اللهِ، أَخْرَجُوكَ وَكَذَّبُوكَ، قَرِّبْهُمْ فَاضْرِبْ أَعْنَاقَهُمْ، قَالَ: وَقَالَ عَبْدُ اللهِ بْنُ رَوَاحَةَ: يَا رَسُولَ اللهِ، انْظُرْ وَادِياً كَثِيرَ الْحَطَبِ، فَأَدْخِلْهُمْ فِيهِ، ثُمَّ أَضْرِمْ عَلَيْهِمْ نَاراً، قَالَ: فَقَالَ الْعَبَّاسُ: قَطَعْتَ رَحِمَكَ، قَالَ: فَدَخَلَ رَسُولُ اللهِ ﷺ، وَلَمْ يَرُدَّ عَلَيْهِمْ شَيْئًا، قَالَ: فَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ أَبِي بَكْرٍ، وَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ عُمَرَ، وَقَالَ نَاسٌ: يَأْخُذُ بِقَوْلِ عَبْدِ اللهِ بْنِ رَوَاحَةَ، قَالَ: فَخَرَجَ عَلَيْهِمْ رَسُولُ اللهِ ﷺ، فَقَالَ: « إِنَّ الله لَيُلِينُ قُلُوبَ رِجَالٍ فِيهِ، حَتَّى تَكُونَ أَلْيَنَ مِنْ اللَّبَنِ، وَإِنَّ اللهَ لَيَشُدُّ قُلُوبَ رِجَالٍ فِيهِ، حَتَّى تَكُونَ أَشَدَّ مِنْ الْحِجَارَةِ، وَإِنَّ مَثَلَكَ يَا أَبَا بَكْرٍ، كَمَثَلِ إِبْرَاهِيمَ عليه السلام قَالَ: { فَمَن تَبِعَنِى فَإِنَّهُۥ مِنِّى ۖ وَمَنْ عَصَانِى فَإِنَّكَ غَفُورٌ رَّحِيمٌ }، وَمَثَلَكَ يَا أَبَا بَكْرٍ، كَمَثَل عِيسَى، قَالَ: { إِن تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ ۖ وَإِن تَغْفِرْ لَهُمْ فَإِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ ﴿١١٨﴾ }، وَإِنْ مَثَلَكَ يَا عُمَرُ، كَمَثَلِ نُوحٍ، قَالَ: { رَّبِّ لَا تَذَرْ عَلَى ٱلْأَرْضِ مِنَ ٱلْكَـٰفِرِينَ دَيَّارًا }، وَإِنَّ مِثْلَكَ يَا عُمَرُ، كَمَثَلِ مُوسَى، قَالَ: { وَٱشْدُدْ عَلَىٰ قُلُوبِهِمْ فَلَا يُؤْمِنُوا۟ حَتَّىٰ يَرَوُا۟ ٱلْعَذَابَ ٱلْأَلِيمَ }، أَنْتُمْ عَالَةٌ فَلَا يَنْفَلِئَنَّ مِنْهُمْ أَحَدٌ إِلَّا بِفِدَاءٍ، أَوْ ضَرْبَةِ عُنُقٍ »، قَالَ عَبْدُ الله: فَقُلْتُ: يَا رَسُولَ اللهِ، إِلَّا سُهَيْلُ ابْنُ بَيْضَاءَ، فَإِنِّي قَدْ سَمِعْتُهُ يَذْكُرُ الْإِسْلَامَ، قَالَ: فَسَكَتَ، قَالَ: فَمَا رَأَيْتُنِي فِي يَوْمٍ، أَخْوَفَ أَنْ تَقَعَ عَلَيَّ حِجَارَةٌ مِنْ السَّمَاءِ، فِي ذَلِكَ الْيَوْمِ حَتَّى قَالَ: « إِلَّا سُهَيْلُ ابْنُ بَيْضَاءَ »، قَالَ: فَأَنْزَلَ اللهُ عز و جل { مَا كَانَ لِنَبِىٍّ أَن يَكُونَ لَهُۥٓ أَسْرَىٰ حَتَّىٰ يُثْخِنَ فِى ٱلْأَرْضِ ۚ تُرِيدُونَ عَرَضَ ٱلدُّنْيَا وَٱللَّهُ يُرِيدُ ٱلْـَٔاخِرَةَ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ ﴿٦٧﴾ } إِلَى قَوْلِهِ { لَّوْلَا كِتَٰبٌ مِّنَ ٱللَّهِ سَبَقَ لَمَسَّكُمْ فِيمَآ أَخَذْتُمْ عَذَابٌ عَظِيمٌ ﴿٦٨﴾ }. واللفظ لأحمد.\n\nوقد جاء عن ابن عمر عن النبي ﷺ شبيهاً به.\n\nوقد جاء عَنْ أَنَسٍ له شبيهاً بما جاء عن ابن عباس.","id":""}],"70":[{"ar":"عن عائشة رضي الله تعالى عنها قالت: ( لما بعث أهل مكة في فداء أسراهم، بعثت زينب بنت رسول الله ﷺ في فداء أبي العاص،...) (... وقال العباس: يا رسول الله، إني كنت مسلماً، فقال رسول الله ﷺ: « الله أعلم بإسلامك، فإن يكن كما تقول فالله يجزيك، فافد نفسك وابنَيْ أخويك نوفل بن الحارث بن عبد المطلب، وعقيل بن أبي طالب بن عبد المطلب، وحليفك عتبة بن عمرو بن جحدم أخو بني الحارث بن فهر » فقال: ما ذاك عندي يا رسول الله، قال: « فأين المال الذي دفنت أنت وأم الفضل، فقلت لها: إن أصبت فهذا المال لبني الفضل، وعبد الله، وقثم » فقال: والله يا رسول الله إني أعلم أنك رسوله، إن هذا لشيء ما علمه أحد غيري وغير أم الفضل، فاحتسب لي يا رسول الله ما أصبتم من عشرين أوقية من مال كان معي.\n\nفقال رسول الله ﷺ: « أفعل »، فقدى العباس نفسه وابن أخويه وحليفه وأنزل الله فيها: { يَـٰٓأَيُّهَا ٱلنَّبِىُّ قُل لِّمَن فِىٓ أَيْدِيكُم مِّنَ ٱلْأَسْرَىٰٓ إِن يَعْلَمِ ٱللَّهُ فِى قُلُوبِكُمْ خَيْرًا يُؤْتِكُمْ خَيْرًا مِّمَّآ أُخِذَ مِنكُمْ وَيَغْفِرْ لَكُمْ ۗ وَٱللَّهُ غَفُورٌ رَّحِيمٌ ﴿٧٠﴾ } وأعطاني الله مكان العشرين الأوقية في الإسلام، عشرين عبداً كلهم في يده مال يضرب به، مع ما أرجو من مغفرة الله عز و جل.\n\nوقد جاء عن ابن عباس رضي الله عنهما شبيهاً من حديث عائشة.","id":""}],"75":[{"ar":"عن الزبير بن العوام رضي الله عنه قال: أنزل الله عز و جل فينا خاصة معشر قريش والأنصار: { وَأُو۟لُوا۟ ٱلْأَرْحَامِ بَعْضُهُمْ أَوْلَىٰ بِبَعْضٍ }، وذلك أنا معشر قريش لما قدمنا المدينة، قدمنا ولا أموال لنا، فوجدنا الأنصار نعم الإخوان، فواخيناهم، ووارثناهم، فأخي أبو بكر رضي الله عنه خارجة بن زيد، وآخي عمر رضي الله عنه فلاناً، وأخي عثمان رضي الله عنه رجلاً من بني زريق بن سعد الزرقي، ويقول بعض الناس غيره، قال الزبير رضي الله عنه: وواخيت أنا كعب بن مالك، ووارثونا ووارثناهم، فلما كان يوم أحد، قيل لي، قد قتل أخوك كعب بن مالك، فجئته فانتقلته فوجدت السلاح قد ثقله فيما يرى. فوالله يا بني لو مات يومئذٍ عن الدنيا ما ورثه غيري، حتى أنزل الله تعالى هذه الآية فينا معشر قريش والأنصار خاصة، فرجعنا إلى مواريثنا.","id":""}]},"mapping_ayat":{"8:38":[{"p":"Muslim","n":139,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ ح و حَدَّثَنَا أَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ أَبِي مُعَاوِيَةَ كِلَاهُمَا عَنْ الْأَعْمَشِ عَنْ أَبِي ظِبْيَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ وَهَذَا حَدِيثُ ابْنِ أَبِي شَيْبَةَ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَصَبَّحْنَا الْحُرَقَاتِ مِنْ جُهَيْنَةَ فَأَدْرَكْتُ رَجُلًا فَقَالَ لَا إِلَهَ إِلَّا اللَّهُ فَطَعَنْتُهُ فَوَقَعَ فِي نَفْسِي مِنْ ذَلِكَ فَذَكَرْتُهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَقَتَلْتَهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا قَالَهَا خَوْفًا مِنْ السِّلَاحِ قَالَ أَفَلَا شَقَقْتَ عَنْ قَلْبِهِ حَتَّى تَعْلَمَ أَقَالَهَا أَمْ لَا فَمَا زَالَ يُكَرِّرُهَا عَلَيَّ حَتَّى تَمَنَّيْتُ أَنِّي أَسْلَمْتُ يَوْمَئِذٍ قَالَ فَقَالَ سَعْدٌ وَأَنَا وَاللَّهِ لَا أَقْتُلُ مُسْلِمًا حَتَّى يَقْتُلَهُ ذُو الْبُطَيْنِ يَعْنِي أُسَامَةَ قَالَ قَالَ رَجُلٌ أَلَمْ يَقُلْ اللَّهُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ وَيَكُونَ الدِّينُ كُلُّهُ لِلَّهِ }فَقَالَ سَعْدٌ قَدْ قَاتَلْنَا حَتَّى لَا تَكُونَ فِتْنَةٌ وَأَنْتَ وَأَصْحَابُكَ تُرِيدُونَ أَنْ تُقَاتِلُوا حَتَّى تَكُونُ فِتْنَةٌ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid al-Ahmar]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Abu Kuraib] dan [Ishaq bin Ibrahim] dari [Abu Mu'awiyah] keduanya dari [al-A'masy] dari [Abu Dlibyan] dari [Usamah bin Zaid] dan ini hadits Ibnu Abu Syaibah, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutuskan kami dalam suatu pasukan. Suatu pagi kami sampai di al-Huruqat, yakni suatu tempat di daerah Juhainah. Kemudian aku berjumpa seorang lelaki, lelaki tersebut lalu mengucakan LAA ILAAHA ILLAALLAHU (Tidak ada tuhan yang berhak disembah selain Allah), namun aku tetap menikamnya. Lalu aku merasa ada ganjalan dalam diriku karena hal tersebut, sehingga kejadian tersebut aku ceritakan kepada Rasulullah. Rasulullah lalu bertanya: 'Kenapa kamu membunuh orang yang telah mengucapkan Laa Ilaaha Illaahu? ' Aku menjawab, \"Wahai Rasulullah! Sesungguhnya lelaki itu mengucap demikian karena takutkan ayunan pedang.\" Rasulullah bertanya lagi: \"Sudahkah kamu membelah dadanya sehingga kamu tahu dia benar-benar mengucapkan Kalimah Syahadat atau tidak?\" Rasulullah terus mengulangi pertanyaan itu kepadaku hingga menyebabkan aku berandai-andai bahwa aku baru masuk Islam saat itu.\" Usamah menceritakan lagi, \"Sa'd telah berkata, 'Demi Allah, aku tidak akan membunuh seorang muslim, hingga dia telah dibunuh oleh orang yang mempunyai perut yang kecil, yaitu Usamah.' Usamah berkata lagi, 'Seorang lelaki telah bertanya, 'Tidakkah Allah telah berfirman, '(Dan perangilah mereka, sehingga tiada lagi fitnah, dan jadikanlah agama itu semata-mata karena Allah) ' (Qs. Al Anfal: 38). Maka Sa'd menjawab, \"Sesungguhnya kami memerangi mereka supaya tidak berlaku fitnah, tetapi kamu dan para Sahabat kamu memerangi mereka, untuk menimbulkan fitnah.\""}],"8:39":[{"p":"Ibnu Majah","n":3884,"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَاصِمٍ عَنْ السُّمَيْطِ بْنِ السَّمِيرِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَأَتَى نَافِعُ بْنُ الْأَزْرَقِ وَأَصْحَابُهُ فَقَالُوا هَلَكْتَ يَا عِمْرَانُ قَالَ مَا هَلَكْتُ قَالُوا بَلَى قَالَ مَا الَّذِي أَهْلَكَنِي قَالُوا قَالَ اللَّهُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ وَيَكُونَ الدِّينُ كُلُّهُ لِلَّهِ }قَالَ قَدْ قَاتَلْنَاهُمْ حَتَّى نَفَيْنَاهُمْ فَكَانَ الدِّينُ كُلُّهُ لِلَّهِ إِنْ شِئْتُمْ حَدَّثْتُكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَأَنْتَ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ بَعَثَ جَيْشًا مِنْ الْمُسْلِمِينَ إِلَى الْمُشْرِكِينَ فَلَمَّا لَقُوهُمْ قَاتَلُوهُمْ قِتَالًا شَدِيدًا فَمَنَحُوهُمْ أَكْتَافَهُمْ فَحَمَلَ رَجُلٌ مِنْ لُحْمَتِي عَلَى رَجُلٍ مِنْ الْمُشْرِكِينَ بِالرُّمْحِ فَلَمَّا غَشِيَهُ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ إِنِّي مُسْلِمٌ فَطَعَنَهُ فَقَتَلَهُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكْتُ قَالَ وَمَا الَّذِي صَنَعْتَ مَرَّةً أَوْ مَرَّتَيْنِ فَأَخْبَرَهُ بِالَّذِي صَنَعَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا شَقَقْتَ عَنْ بَطْنِهِ فَعَلِمْتَ مَا فِي قَلْبِهِ قَالَ يَا رَسُولَ اللَّهِ لَوْ شَقَقْتُ بَطْنَهُ لَكُنْتُ أَعْلَمُ مَا فِي قَلْبِهِ قَالَ فَلَا أَنْتَ قَبِلْتَ مَا تَكَلَّمَ بِهِ وَلَا أَنْتَ تَعْلَمُ مَا فِي قَلْبِهِ قَالَ فَسَكَتَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَلْبَثْ إِلَّا يَسِيرًا حَتَّى مَاتَ فَدَفَنَّاهُ فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَقَالُوا لَعَلَّ عَدُوًّا نَبَشَهُ فَدَفَنَّاهُ ثُمَّ أَمَرْنَا غِلْمَانَنَا يَحْرُسُونَهُ فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَقُلْنَا لَعَلَّ الْغِلْمَانَ نَعَسُوا فَدَفَنَّاهُ ثُمَّ حَرَسْنَاهُ بِأَنْفُسِنَا فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَأَلْقَيْنَاهُ فِي بَعْضِ تِلْكَ الشِّعَابِحَدَّثَنَا إِسْمَعِيلُ بْنُ حَفْصٍ الْأَيْلِيُّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَاصِمٍ عَنْ السُّمَيْطِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَ بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَحَمَلَ رَجُلٌ مِنْ الْمُسْلِمِينَ عَلَى رَجُلٍ مِنْ الْمُشْرِكِينَ فَذَكَرَ الْحَدِيثَ وَزَادَ فِيهِ فَنَبَذَتْهُ الْأَرْضُ فَأُخْبِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّ الْأَرْضَ لَتَقْبَلُ مَنْ هُوَ شَرٌّ مِنْهُ وَلَكِنَّ اللَّهَ أَحَبَّ أَنْ يُرِيَكُمْ تَعْظِيمَ حُرْمَةِ لَا إِلَهَ إِلَّا اللَّهُ","trj":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari ['Ashim] dari [As Sumaith bin As Samir] dari ['Imran bin Al Hushin] dia berkata, \"Nafi' bin Al Azraq bersama para sahabatnya, mereka berkata, \"Celaka kamu wahai 'Imran! \" Imran pun bertanya, \"Aku celaka! \" mereka menjawab, \"Ya.\" Imran bertanya lagi, \"Apa yang mencelakakanku?\" mereka menjawab, \"Allah telah berfirman '(dan perangilah mereka sehingga tidak ada fitnah dan yang ada hanya agama milik Allah saja) ' (Qs. Al Anfal: 39). Imran berkata, \"Kami telah memerangi mereka dan memberangusnya, sehingga din ini hanya milik Allah saja. Kalau kalian kehendaki, aku akan ceritakan kepada kalian suatu hadits yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam.\" Mereka berkata, \"Dan kamu (benar-benar) mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?.\" Imran menjawab, \"Ya. Aku menyaksikan Rasulullah shallallahu 'alaihi wasallam mengutus pasukan kaum muslimin untuk menyerang kaum musyrikin, tatkala mereka bertemu musuh, mereka pun memeranginya dengan pertempuran sengit hingga berhasil mengalahkan musuh. Lalu salah seorang dari familiku dapat menodong seorang dari kaum musyrikin dengan tombak, ketika saudaraku mendatanginya ia berkata, \"Aku bersaksi bahwa tidak ada tuhan yang berhak disembah selain Allah, aku adalah seorang muslim.\" Tetapi familiku itu tetap menikamnya sehingga ia mati. Kemudian saudaraku datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Celaka aku wahai Rasulullah! \" Beliau bertanya sekali atau dua kali: \"Apa yang telah kamu lakukan?\" Dia memberitahukan kepada beliau apa yang dia perbuat. Rasulullah shallallahu 'alaihi wasallam pun bersabda kepadanya: \"Apakah kamu harus membelah perutnya sehingga kamu dapat mengetahui apa yang ada di dalam hatinya?\" Dia menjawab, \"Ya Rasulullah, kalau seandainya aku (memang harus) membelah perutnya niscaya aku mengetahui apa yang ada di dalam hatinya.\" Beliau bertanya: \"Lalu kenapa kamu tidak terima apa yang dia ucapkan sedang kamu tidak mengetahui apa yang ada dalam hatinya?\" 'Imran berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam mendiamkannya. Dan tidak lama kemudian, orang itu pun meninggal dunia. Maka kami menguburkannya. Di pagi harinya (jenazahnya) telah berada di atas permukaan tanah. Mereka berkata, \"Jangan-jangan ada musuh yang sengaja mengeluarkannya.\" Maka kami menguburnya kemudian memerintahkan kepada budak-budak kami untuk menjaganya, tetapi (jenazahnya) kembali berada di atas permukaan tanah. Maka kami berkata, \"Jangan-jangan budak-budak itu telah ngantuk.\" Kemudian kami menjaganya sendiri tetapi (jenazahnya) tetap berada di atas permukaan tanah sehingga kami melemparkannya di celah yang terletak di antara dua bukit.\" Telah menceritakan kepada kami [Isma'il bin Hafsh Al Aili] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari ['Ashim] dari [As Sumaith] dari ['Imran bin AL Hushain] dia berkata, 'Rasulullah shallallahu 'alaihi wasallam mengutus kami di suatu ekspedisi. Kemudian ada seorang dari kaum muslimin menyerang seseorang dari kaum musyrikin…. Kemudian perawi menyebutkan hadits seperti yang di atas, dan dia menambahkan di dalam haditsnya, \"Tetapi bumi membuangnya (mengeluarkannya), kemudian kejadian itu diberitahukan kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Sesungguhnya bumi menerima orang yang lebih buruk dari dia, tetapi Allah ingin memperlihatkan kepada kalian pengagungan terhadap kehormatan kalimat Laa Ilaaha Illallah.\""}],"8:72":[{"p":"Bukhari","n":1485,"ar":"حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَيْنَ تَنْزِلُ فِي دَارِكَ بِمَكَّةَ فَقَالَ وَهَلْ تَرَكَ عَقِيلٌ مِنْ رِبَاعٍ أَوْ دُورٍ وَكَانَ عَقِيلٌ وَرِثَ أَبَا طَالِبٍ هُوَ وَطَالِبٌ وَلَمْ يَرِثْهُ جَعْفَرٌ وَلَا عَلِيٌّ رَضِيَ اللَّهُ عَنْهُمَا شَيْئًا لِأَنَّهُمَا كَانَا مُسْلِمَيْنِ وَكَانَ عَقِيلٌ وَطَالِبٌ كَافِرَيْنِ فَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُ لَا يَرِثُ الْمُؤْمِنُ الْكَافِرَ قَالَ ابْنُ شِهَابٍ وَكَانُوا يَتَأَوَّلُونَ قَوْلَ اللَّهِ تَعَالَى{ إِنَّ الَّذِينَ آمَنُوا وَهَاجَرُوا ��َجَاهَدُوا بِأَمْوَالِهِمْ وَأَنْفُسِهِمْ فِي سَبِيلِ اللَّهِ وَالَّذِينَ آوَوْا وَنَصَرُوا أُولَئِكَ بَعْضُهُمْ أَوْلِيَاءُ بَعْضٍ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ashbagh] berkata, telah mengabarkan kepada saya [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari ['Ali bin Husain] dari ['Amru bin 'Utsman] dari [Usamah bin Zaid radliallahu 'anhum] bahwa dia berkata: \"Wahai Rasulullah, dimana anda akan singgah di Makkah ini?\". Beliau berkata: \"Apakah 'Uqail meninggalkan rumah yang luas atau rumah-rumah?\". 'Uqail dan Tholib mendapatkan warisan dari Abu Tholib sedangkan Ja'far dan 'Ali radliallahu 'anhuma tidak mewarisi sedikitpun karena keduanya adalah Muslim sedangkan 'Uqail dan Tholib kafir. Dan adalah 'Umar bin Al Khaththob radliallahu 'anhu berkata: \"Seorang mu'min tidak mewariskan kepada orang yang kafir\". Ibnu Syihab berkata: \"Mereka menafsirkan firman Allah Ta'ala QS Al Anfal ayat 72 (yang artinya): (\"Sesungguhnya orang-orang yang beriman, orang-orang yang berhijrah dan orang-orang yang berjihad dengan harta dan jiwa mereka di jalan Allah dan orang-orang yang memberikan tempat kediaman dan menolong (orang yang berhijrah) mereka itu satu sama lain saling melindungi\"). "}]},"mapping_surah":[{"p":"Abu Dawud","n":655,"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ عَنْ عَوْفٍ عَنْ يَزِيدَ الْفَارِسِيِّ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ قَالَقُلْتُ لِعُثْمَانَ بْنِ عَفَّانَ مَا حَمَلَكُمْ أَنْ عَمَدْتُمْ إِلَى بَرَاءَةَ وَهِيَ مِنْ الْمِئِينَ وَإِلَى الْأَنْفَالِ وَهِيَ مِنْ الْمَثَانِي فَجَعَلْتُمُوهُمَا فِي السَّبْعِ الطِّوَالِ وَلَمْ تَكْتُبُوا بَيْنَهُمَا سَطْرَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ قَالَ عُثْمَانُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا تَنَزَّلُ عَلَيْهِ الْآيَاتُ فَيَدْعُو بَعْضَ مَنْ كَانَ يَكْتُبُ لَهُ وَيَقُولُ لَهُ ضَعْ هَذِهِ الْآيَةَ فِي السُّورَةِ الَّتِي يُذْكَرُ فِيهَا كَذَا وَكَذَا وَتَنْزِلُ عَلَيْهِ الْآيَةُ وَالْآيَتَانِ فَيَقُولُ مِثْلَ ذَلِكَ وَكَانَتْ الْأَنْفَالُ مِنْ أَوَّلِ مَا أُنْزِلَ عَلَيْهِ بِالْمَدِينَةِ وَكَانَتْ بَرَاءَةُ مِنْ آخِرِ مَا نَزَلَ مِنْ الْقُرْآنِ وَكَانَتْ قِصَّتُهَا شَبِيهَةً بِقِصَّتِهَا فَظَنَنْتُ أَنَّهَا مِنْهَا فَمِنْ هُنَاكَ وَضَعْتُهَا فِي السَّبْعِ الطِّوَالِ وَلَمْ أَكْتُبْ بَيْنَهُمَا سَطْرَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِحَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا مَرْوَانُ يَعْنِي ابْنَ مُعَاوِيَةَ أَخْبَرَنَا عَوْفٌ الْأَعْرَابِيُّ عَنْ يَزِيدَ الْفَارِسِيِّ حَدَّثَنَا ابْنُ عَبَّاسٍ بِمَعْنَاهُ قَالَ فِيهِ فَقُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يُبَيِّنْ لَنَا أَنَّهَا مِنْهَا قَالَ أَبُو دَاوُد قَالَ الشَّعْبِيُّ وَأَبُو مَالِكٍ وَقَتَادَةُ وَثَابِتُ بْنُ عُمَارَةَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكْتُبْ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَتَّى نَزَلَتْ سُورَةُ النَّمْلِ هَذَا مَعْنَاهُ","trj":"Telah mengabarkan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Husyaim] dari ['Auf] dari [Yazid Al Farisi] dia berkata; saya mendengar [Ibnu Abbas] berkata; aku bertanya kepada Utsman bin 'Affan; \"Apa yang menyebabkan kalian sengaja meletakkan surat surat Bara'ah (At Taubah) padahal dia termasuk dari mi`in (surat yang ayatnya sampai seratus) dan surat Al Anfal padahal dia termasuk dari al matsani (surat yang ayatnya kurang dari seratus) kemudian kalian menyatukan keduanya termasuk dari tujuh surat panjang, dan belum kalian tulis antara keduanya dengan batas \"bismillaahir rahmaanir rahim?\" [Utsman] berkata; \"Ketika beberapa ayat turun kepada Nabi shallallahu 'alaihi wasallam, maka beliau memanggil beberapa orang yang akan menuliskan di sisinya, kemudian beliau bersabda kepadanya: \"Letakkan ayat ini dalam surat yang disebutkan di dalamnya begini dan begini, \" Ketika turun kepada beliau satu ayat atau dua ayat, maka beliau akan mengatakan seperti itu. Surat Al Anfal termasuk dari surat yang pertama diturunkan di Madinah, sedangkan Bara'ah (At Taubah) termasuk dari surat yang terakhir diturunkan di Madinah, sementara kandungannya mirip dengan kandungan yang ada dalam surat Al Anfal, maka perkiraanku, surat Al Bara'ah bagian dari surat Al Anfal, oleh karena itu aku meletakkan surat tersebut termasuk dari tujuh surat yang panjang, sehingga aku tidak menulis dengan batasan \"Bismillahir rahmanir rahim.\" Telah menceritakan kepada kami [Ziyad bin Ayyub] telah menceritakan kepada kami [Marwan yaitu Ibnu Mu'awiyah] telah mengabarkan kepada kami ['Auf Al A'Rabi'ah] dari [Yazid Al Farisi] telah menceritakan kepada kami [Ibnu Abbas] semakna dengan hadits di atas, dalam hadits tersebut dia mengatakan; \"Rasulullah shallallahu 'alaihi wasallam telah wafat, namun beliau belum menjelaskan kepada kami jika surat Al Anfal bagian dari surat Al Bara'ah.\" Abu Daud berkata; As Sya'bi, Abu Malik, Qatadah dan Tsabit bin 'Umarah mengatakan; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam tidak menulis \"Bismillahir rahmaanir rahim\" hingga turun surat An Naml, demikian makna dari hadits tersebut.\""},{"p":"Abu Dawud","n":2466,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ فَآتُوهُمْ نَصِيبَهُمْ }كَانَ الرَّجُلُ يُحَالِفُ الرَّجُلَ لَيْسَ بَيْنَهُمَا نَسَبٌ فَيَرِثُ أَحَدُهُمَا الْآخَرَ فَنَسَخَ ذَلِكَ الْأَنْفَالُ فَقَالَ تَعَالَى{ وَأُولُو الْأَرْحَامِ بَعْضُهُمْ أَوْلَى بِبَعْضٍ }","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit], telah menceritakan kepadaku [Ali bin Husain], dari [ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; firman Allah: \"Dan (jika ada) orang-orang yang kamu telah bersumpah setia dengan mereka, maka berilah kepada mereka bagiannya.\" Dahulu seorang laki-laki saling bersumpah dengan orang lain yang tidak memiliki nasab dengannya, kemudian yang satu mewarisi yang lainnya. Kemudian hal tersebut dihapuskan oleh Surat Al Anfal: \"Orang-orang yang mempunyai hubungan kerabat itu sebagiannya lebih berhak terhadap sesamanya (daripada yang bukan kerabat) \""},{"p":"Ahmad","n":20,"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ دُعِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلصَّلَاةِ عَلَيْهِ فَقَامَ إِلَيْهِ فَلَمَّا وَقَفَ عَلَيْهِ يُرِيدُ الصَّلَاةَ تَحَوَّلْتُ حَتَّى قُمْتُ فِي صَدْرِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَعَلَى عَدُوِّ اللَّهِ عَبْدِ اللَّهِ بْنِ أُبَيٍّ الْقَائِلِ يَوْمَ كَذَا كَذَا وَكَذَا يُعَدِّدُ أَيَّامَهُ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ حَتَّى إِذَا أَكْثَرْتُ عَلَيْهِ قَالَ أَخِّرْ عَنِّي يَا عُمَرُ إِنِّي خُيِّرْتُ فَاخْتَرْتُ وَقَدْ قِيلَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ قَالَ ثُمَّ صَلَّى عَلَيْهِ وَمَشَى مَعَهُ فَقَامَ عَلَى قَبْرِهِ حَتَّى فُرِغَ مِنْهُ قَالَ فَعَجَبٌ لِي وَجَرَاءَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَوَاللَّهِ مَا كَانَ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ هَاتَانِ الْآيَتَانِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }فَمَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَهُ عَلَى مُنَافِقٍ وَلَا قَامَ عَلَى قَبْرِهِ حَتَّى قَبَضَهُ اللَّهُ عَزَّ وَجَلَّ","trj":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] Telah menceritakan kepadaku [Az Zuhri] dari [Ubaidullah Bin Abdullah Bin 'Utbah Bin Mas'ud] dari [Abdullah bin Abbas], dia berkata; aku mendengar [Umar Bin Khattab] berkata; ketika Abdullah Bin Ubai meninggal, Rasulullah shallallahu 'alaihi wasallam dipanggil untuk menshalatinya, maka beliau bergegas mendatanginya, tatkala beliau berdiri dihadapannya untuk menshalatinya aku menghalanginya sehingga aku berdiri dihadapan beliau dan berkata; \"Wahai Rasulullah, Abdullah Bin Ubai adalah dedengkot musuh Allah yang mengatakan pada hari ini dan ini, \" dia menyebutkan nama nama harinya, kemudian Umar melanjutkan; akan tetapi Rasulullah shallallahu 'alaihi wasallam hanya tersenyum sampai ketika aku mengulang-ngulang perkataanku beliau berkata: \"Minggirlah dariku wahai Umar, sesungguhnya aku di beri pilihan maka aku memilih, dan sudah di sebutkan: \"Kamu memohonkan ampun bagi mereka atau tidak kamu mohonkan ampun bagi mereka (adalah sama saja). kendatipun kamu memohonkan ampun bagi mereka tujuh puluh kali, namun Allah sekali-kali tidak akan memberi ampunan kepada mereka.'\" (QS Al Anfal ayat 80) seandainya aku tahu apabila aku menambah permohonanku sampai tujuh puluh kali dia akan mendapat ampunan niscaya aku akan tambah\" Umar berkata; kemudian beliau menshalatinya dan mengantarkan jenazahnya lalu berdiri di atas kuburannya sampai selesai dimakamkan, \" Umar berkata; \"aku heran dengan diriku atas lancangnya diriku kepada Rasulullah shallallahu 'alaihi wasallam, padahal Allah dan Rasul-Nya lebih tahu\" Umar berkata lagi; \"maka demi Allah tidak lama kemudian turunlah dua ayat ini (QS At Taubah ayat 80, 84).\"Dan janganlah kamu sekali-kali menyembahyangkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendoakan) di kuburnya. Sesungguhnya mereka Telah kafir kepada Allah dan rasul-Nya dan mereka mati dalam keadaan fasik\". Kemudian Rasulullah shallallahu 'alaihi wasallam setelah itu tidak pernah lagi menshalati orang munafiq dan tidak juga berdiri di atas quburannya."},{"p":"Bukhari","n":1485,"ar":"حَدَّثَنَا أَصْبَغُ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَيَا رَسُولَ اللَّهِ أَيْنَ تَنْزِلُ فِي دَارِكَ بِمَكَّةَ فَقَالَ وَهَلْ تَرَكَ عَقِيلٌ مِنْ رِبَاعٍ أَوْ دُورٍ وَكَانَ عَقِيلٌ وَرِثَ أَبَا طَالِبٍ هُوَ وَطَالِبٌ وَلَمْ يَرِثْهُ جَعْفَرٌ وَلَا عَلِيٌّ رَضِيَ اللَّهُ عَنْهُمَا شَيْئًا لِأَنَّهُمَا كَانَا مُسْلِمَيْنِ وَكَانَ عَقِيلٌ وَطَالِبٌ كَافِرَيْنِ فَكَانَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُ لَا يَرِثُ الْمُؤْمِنُ الْكَافِرَ قَالَ ابْنُ شِهَابٍ وَكَانُوا يَتَأَوَّلُونَ قَوْلَ اللَّهِ تَعَالَى{ إِنَّ الَّذِينَ آمَنُوا وَهَاجَرُوا ��َجَاهَدُوا بِأَمْوَالِهِمْ وَأَنْفُسِهِمْ فِي سَبِيلِ اللَّهِ وَالَّذِينَ آوَوْا وَنَصَرُوا أُولَئِكَ بَعْضُهُمْ أَوْلِيَاءُ بَعْضٍ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ashbagh] berkata, telah mengabarkan kepada saya [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari ['Ali bin Husain] dari ['Amru bin 'Utsman] dari [Usamah bin Zaid radliallahu 'anhum] bahwa dia berkata: \"Wahai Rasulullah, dimana anda akan singgah di Makkah ini?\". Beliau berkata: \"Apakah 'Uqail meninggalkan rumah yang luas atau rumah-rumah?\". 'Uqail dan Tholib mendapatkan warisan dari Abu Tholib sedangkan Ja'far dan 'Ali radliallahu 'anhuma tidak mewarisi sedikitpun karena keduanya adalah Muslim sedangkan 'Uqail dan Tholib kafir. Dan adalah 'Umar bin Al Khaththob radliallahu 'anhu berkata: \"Seorang mu'min tidak mewariskan kepada orang yang kafir\". Ibnu Syihab berkata: \"Mereka menafsirkan firman Allah Ta'ala QS Al Anfal ayat 72 (yang artinya): (\"Sesungguhnya orang-orang yang beriman, orang-orang yang berhijrah dan orang-orang yang berjihad dengan harta dan jiwa mereka di jalan Allah dan orang-orang yang memberikan tempat kediaman dan menolong (orang yang berhijrah) mereka itu satu sama lain saling melindungi\"). "},{"p":"Bukhari","n":3973,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ أَخْبَرَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاسُورَةُ الْأَنْفَالِ قَالَ نَزَلَتْ فِي بَدْرٍالشَّوْكَةُ الْحَدُّ{ مُرْدَفِينَ }فَوْجًا بَعْدَ فَوْجٍ رَدِفَنِي وَأَرْدَفَنِي جَاءَ بَعْدِي{ ذُوقُوا }بَاشِرُوا وَجَرِّبُوا وَلَيْسَ هَذَا مِنْ ذَوْقِ الْفَمِ{ فَيَرْكُمَهُ }يَجْمَعَهُ شَرِّدْ فَرِّقْ{ وَإِنْ جَنَحُوا }طَلَبُوا السِّلْمُ وَالسَّلْمُ وَالسَّلَامُ وَاحِدٌ{ يُثْخِنَ }يَغْلِبَ وَقَالَ مُجَاهِدٌ{ مُكَاءً }إِدْخَالُ أَصَابِعِهِمْ فِي أَفْوَاهِهِمْ{ وَتَصْدِيَةً }الصَّفِيرُ{ لِيُثْبِتُوكَ }لِيَحْبِسُوكَ","trj":"Telah menceritakan kepadaku [Muhammad bin 'Abdur Rahim] Telah menceritakan kepada kami [Sa'id bin Sulaiman] Telah mengabarkan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dia berkata; Aku bertanya kepada [Ibnu 'Abbas radliallahu 'anhuma] surat Al Anfal, lalu dia menjawab; 'Yaitu surat yang diturunkan di perang Badar. Perang yang penuh onak dan duri. MURDIFIN artinya; datang bertubi-tubi, hingga cukup melelahkanku dan orang yang datang setelahku. DZUQUU, artinya; berilah kabar gembira, dan berusahalah terus. Ini bukan rasa yang bisa diketahui melalui mulut. FAYARKUMUHU artinya; bergabung dan berpencar. WA IN JANAHU artinya jika mereka meminta keselamatan dan keamanan atau berdamai (satu makna). YUSKHINA artinya: kekalahan. Mujahid berkata; arti MUKAA`AN yaitu memasukan jari-jari mereka ke dalam mulut-mulut mereka. Arti TASHDIYAH; suara yang memekakkan. LIYUTSBITUTKA artinya; untuk menahanmu."},{"p":"Bukhari","n":4198,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍسُورَةُ التَّوْبَةِ قَالَ التَّوْبَةُ هِيَ الْفَاضِحَةُ مَا زَالَتْ تَنْزِلُ وَمِنْهُمْ وَمِنْهُمْ حَتَّى ظَنُّوا أَنَّهَا لَنْ تُبْقِيَ أَحَدًا مِنْهُمْ إِلَّا ذُكِرَ فِيهَا قَالَ قُلْتُ سُورَةُ الْأَنْفَالِ قَالَ نَزَلَتْ فِي بَدْرٍ قَالَ قُلْتُ سُورَةُ الْحَشْرِ قَالَ نَزَلَتْ فِي بَنِي النَّضِيرِ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah menceritakan kepada kami [Sa'id bin Sulaiman] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] ia berkata; Aku pernah bertanya kepada [Ibnu Abbas] mengenai surat At Taubah, maka ia pun menjelaskan, \"Surat At Taubah adalah diistilahkan Al Fadlihah (yang membongkar kejahatan kaum munafik). Ia senantiasa turun dengan ungkapan, 'WA MINHUM.., WA MINHUM.. (Dan di antara mereka.. dan di antara mereka) ' hingga mereka pun menyangka bahwa tidak ada seorang pun yang tersisa dari mereka kecuali disebutkan dalam surat tersebut.\" Kemudian aku bertanya, \"Bagaimana dengan surat Al Anfal? ' Ia menjelaskan, \"Surat itu turun pada saat terjadinya perang Badar.\" Aku bertanya lagi, \"Kalau surat Al Hasyr?\" Ia pun menjelaskan, \"Surat itu turun berkenaan dengan Bani Nadlir.\""},{"p":"Darimi","n":1942,"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ مَرْثَدِ بْنِ عَبْدِ اللَّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَنَّهُ تَلَا هَذِهِ الْآيَةَ { وَأَعِدُّوا لَهُمْ مَا اسْتَطَعْتُمْ مِنْ قُوَّةٍ } أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ","trj":"Telah mengabarkan kepada kami [Abdullah bin Yazid Al Muqri`] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Abu Al Khair Martsad bin Abdullah] dari ['Uqbah bin 'Amir] bahwa beliau pernah membaca ayat ini: \" Dan siapkanlah untuk menghadapi mereka kekuatan apa saja yang kamu sanggupi.\" QS Al Anfal; 60, ketahuilah sesungguhnya kekuatan itu adalah melempar.\""},{"p":"Ibnu Majah","n":3884,"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَاصِمٍ عَنْ السُّمَيْطِ بْنِ السَّمِيرِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَأَتَى نَافِعُ بْنُ الْأَزْرَقِ وَأَصْحَابُهُ فَقَالُوا هَلَكْتَ يَا عِمْرَانُ قَالَ مَا هَلَكْتُ قَالُوا بَلَى قَالَ مَا الَّذِي أَهْلَكَنِي قَالُوا قَالَ اللَّهُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ وَيَكُونَ الدِّينُ كُلُّهُ لِلَّهِ }قَالَ قَدْ قَاتَلْنَاهُمْ حَتَّى نَفَيْنَاهُمْ فَكَانَ الدِّينُ كُلُّهُ لِلَّهِ إِنْ شِئْتُمْ حَدَّثْتُكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَأَنْتَ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ شَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ بَعَثَ جَيْشًا مِنْ الْمُسْلِمِينَ إِلَى الْمُشْرِكِينَ فَلَمَّا لَقُوهُمْ قَاتَلُوهُمْ قِتَالًا شَدِيدًا فَمَنَحُوهُمْ أَكْتَافَهُمْ فَحَمَلَ رَجُلٌ مِنْ لُحْمَتِي عَلَى رَجُلٍ مِنْ الْمُشْرِكِينَ بِالرُّمْحِ فَلَمَّا غَشِيَهُ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ إِنِّي مُسْلِمٌ فَطَعَنَهُ فَقَتَلَهُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكْتُ قَالَ وَمَا الَّذِي صَنَعْتَ مَرَّةً أَوْ مَرَّتَيْنِ فَأَخْبَرَهُ بِالَّذِي صَنَعَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا شَقَقْتَ عَنْ بَطْنِهِ فَعَلِمْتَ مَا فِي قَلْبِهِ قَالَ يَا رَسُولَ اللَّهِ لَوْ شَقَقْتُ بَطْنَهُ لَكُنْتُ أَعْلَمُ مَا فِي قَلْبِهِ قَالَ فَلَا أَنْتَ قَبِلْتَ مَا تَكَلَّمَ بِهِ وَلَا أَنْتَ تَعْلَمُ مَا فِي قَلْبِهِ قَالَ فَسَكَتَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَلْبَثْ إِلَّا يَسِيرًا حَتَّى مَاتَ فَدَفَنَّاهُ فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَقَالُوا لَعَلَّ عَدُوًّا نَبَشَهُ فَدَفَنَّاهُ ثُمَّ أَمَرْنَا غِلْمَانَنَا يَحْرُسُونَهُ فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَقُلْنَا لَعَلَّ الْغِلْمَانَ نَعَسُوا فَدَفَنَّاهُ ثُمَّ حَرَسْنَاهُ بِأَنْفُسِنَا فَأَصْبَحَ عَلَى ظَهْرِ الْأَرْضِ فَأَلْقَيْنَاهُ فِي بَعْضِ تِلْكَ الشِّعَابِحَدَّثَنَا إِسْمَعِيلُ بْنُ حَفْصٍ الْأَيْلِيُّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عَاصِمٍ عَنْ السُّمَيْطِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَ بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَحَمَلَ رَجُلٌ مِنْ الْمُسْلِمِينَ عَلَى رَجُلٍ مِنْ الْمُشْرِكِينَ فَذَكَرَ الْحَدِيثَ وَزَادَ فِيهِ فَنَبَذَتْهُ الْأَرْضُ فَأُخْبِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّ الْأَرْضَ لَتَقْبَلُ مَنْ هُوَ شَرٌّ مِنْهُ وَلَكِنَّ اللَّهَ أَحَبَّ أَنْ يُرِيَكُمْ تَعْظِيمَ حُرْمَةِ لَا إِلَهَ إِلَّا اللَّهُ","trj":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Ali bin Mushir] dari ['Ashim] dari [As Sumaith bin As Samir] dari ['Imran bin Al Hushin] dia berkata, \"Nafi' bin Al Azraq bersama para sahabatnya, mereka berkata, \"Celaka kamu wahai 'Imran! \" Imran pun bertanya, \"Aku celaka! \" mereka menjawab, \"Ya.\" Imran bertanya lagi, \"Apa yang mencelakakanku?\" mereka menjawab, \"Allah telah berfirman '(dan perangilah mereka sehingga tidak ada fitnah dan yang ada hanya agama milik Allah saja) ' (Qs. Al Anfal: 39). Imran berkata, \"Kami telah memerangi mereka dan memberangusnya, sehingga din ini hanya milik Allah saja. Kalau kalian kehendaki, aku akan ceritakan kepada kalian suatu hadits yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam.\" Mereka berkata, \"Dan kamu (benar-benar) mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?.\" Imran menjawab, \"Ya. Aku menyaksikan Rasulullah shallallahu 'alaihi wasallam mengutus pasukan kaum muslimin untuk menyerang kaum musyrikin, tatkala mereka bertemu musuh, mereka pun memeranginya dengan pertempuran sengit hingga berhasil mengalahkan musuh. Lalu salah seorang dari familiku dapat menodong seorang dari kaum musyrikin dengan tombak, ketika saudaraku mendatanginya ia berkata, \"Aku bersaksi bahwa tidak ada tuhan yang berhak disembah selain Allah, aku adalah seorang muslim.\" Tetapi familiku itu tetap menikamnya sehingga ia mati. Kemudian saudaraku datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Celaka aku wahai Rasulullah! \" Beliau bertanya sekali atau dua kali: \"Apa yang telah kamu lakukan?\" Dia memberitahukan kepada beliau apa yang dia perbuat. Rasulullah shallallahu 'alaihi wasallam pun bersabda kepadanya: \"Apakah kamu harus membelah perutnya sehingga kamu dapat mengetahui apa yang ada di dalam hatinya?\" Dia menjawab, \"Ya Rasulullah, kalau seandainya aku (memang harus) membelah perutnya niscaya aku mengetahui apa yang ada di dalam hatinya.\" Beliau bertanya: \"Lalu kenapa kamu tidak terima apa yang dia ucapkan sedang kamu tidak mengetahui apa yang ada dalam hatinya?\" 'Imran berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam mendiamkannya. Dan tidak lama kemudian, orang itu pun meninggal dunia. Maka kami menguburkannya. Di pagi harinya (jenazahnya) telah berada di atas permukaan tanah. Mereka berkata, \"Jangan-jangan ada musuh yang sengaja mengeluarkannya.\" Maka kami menguburnya kemudian memerintahkan kepada budak-budak kami untuk menjaganya, tetapi (jenazahnya) kembali berada di atas permukaan tanah. Maka kami berkata, \"Jangan-jangan budak-budak itu telah ngantuk.\" Kemudian kami menjaganya sendiri tetapi (jenazahnya) tetap berada di atas permukaan tanah sehingga kami melemparkannya di celah yang terletak di antara dua bukit.\" Telah menceritakan kepada kami [Isma'il bin Hafsh Al Aili] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari ['Ashim] dari [As Sumaith] dari ['Imran bin AL Hushain] dia berkata, 'Rasulullah shallallahu 'alaihi wasallam mengutus kami di suatu ekspedisi. Kemudian ada seorang dari kaum muslimin menyerang seseorang dari kaum musyrikin…. Kemudian perawi menyebutkan hadits seperti yang di atas, dan dia menambahkan di dalam haditsnya, \"Tetapi bumi membuangnya (mengeluarkannya), kemudian kejadian itu diberitahukan kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Sesungguhnya bumi menerima orang yang lebih buruk dari dia, tetapi Allah ingin memperlihatkan kepada kalian pengagungan terhadap kehormatan kalimat Laa Ilaaha Illallah.\""},{"p":"Muslim","n":139,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ ح و حَدَّثَنَا أَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ أَبِي مُعَاوِيَةَ كِلَاهُمَا عَنْ الْأَعْمَشِ عَنْ أَبِي ظِبْيَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ وَهَذَا حَدِيثُ ابْنِ أَبِي شَيْبَةَ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَصَبَّحْنَا الْحُرَقَاتِ مِنْ جُهَيْنَةَ فَأَدْرَكْتُ رَجُلًا فَقَالَ لَا إِلَهَ إِلَّا اللَّهُ فَطَعَنْتُهُ فَوَقَعَ فِي نَفْسِي مِنْ ذَلِكَ فَذَكَرْتُهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَقَتَلْتَهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا قَالَهَا خَوْفًا مِنْ السِّلَاحِ قَالَ أَفَلَا شَقَقْتَ عَنْ قَلْبِهِ حَتَّى تَعْلَمَ أَقَالَهَا أَمْ لَا فَمَا زَالَ يُكَرِّرُهَا عَلَيَّ حَتَّى تَمَنَّيْتُ أَنِّي أَسْلَمْتُ يَوْمَئِذٍ قَالَ فَقَالَ سَعْدٌ وَأَنَا وَاللَّهِ لَا أَقْتُلُ مُسْلِمًا حَتَّى يَقْتُلَهُ ذُو الْبُطَيْنِ يَعْنِي أُسَامَةَ قَالَ قَالَ رَجُلٌ أَلَمْ يَقُلْ اللَّهُ{ وَقَاتِلُوهُمْ حَتَّى لَا تَكُونَ فِتْنَةٌ وَيَكُونَ الدِّينُ كُلُّهُ لِلَّهِ }فَقَالَ سَعْدٌ قَدْ قَاتَلْنَا حَتَّى لَا تَكُونَ فِتْنَةٌ وَأَنْتَ وَأَصْحَابُكَ تُرِيدُونَ أَنْ تُقَاتِلُوا حَتَّى تَكُونُ فِتْنَةٌ","trj":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid al-Ahmar]. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Abu Kuraib] dan [Ishaq bin Ibrahim] dari [Abu Mu'awiyah] keduanya dari [al-A'masy] dari [Abu Dlibyan] dari [Usamah bin Zaid] dan ini hadits Ibnu Abu Syaibah, dia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutuskan kami dalam suatu pasukan. Suatu pagi kami sampai di al-Huruqat, yakni suatu tempat di daerah Juhainah. Kemudian aku berjumpa seorang lelaki, lelaki tersebut lalu mengucakan LAA ILAAHA ILLAALLAHU (Tidak ada tuhan yang berhak disembah selain Allah), namun aku tetap menikamnya. Lalu aku merasa ada ganjalan dalam diriku karena hal tersebut, sehingga kejadian tersebut aku ceritakan kepada Rasulullah. Rasulullah lalu bertanya: 'Kenapa kamu membunuh orang yang telah mengucapkan Laa Ilaaha Illaahu? ' Aku menjawab, \"Wahai Rasulullah! Sesungguhnya lelaki itu mengucap demikian karena takutkan ayunan pedang.\" Rasulullah bertanya lagi: \"Sudahkah kamu membelah dadanya sehingga kamu tahu dia benar-benar mengucapkan Kalimah Syahadat atau tidak?\" Rasulullah terus mengulangi pertanyaan itu kepadaku hingga menyebabkan aku berandai-andai bahwa aku baru masuk Islam saat itu.\" Usamah menceritakan lagi, \"Sa'd telah berkata, 'Demi Allah, aku tidak akan membunuh seorang muslim, hingga dia telah dibunuh oleh orang yang mempunyai perut yang kecil, yaitu Usamah.' Usamah berkata lagi, 'Seorang lelaki telah bertanya, 'Tidakkah Allah telah berfirman, '(Dan perangilah mereka, sehingga tiada lagi fitnah, dan jadikanlah agama itu semata-mata karena Allah) ' (Qs. Al Anfal: 38). Maka Sa'd menjawab, \"Sesungguhnya kami memerangi mereka supaya tidak berlaku fitnah, tetapi kamu dan para Sahabat kamu memerangi mereka, untuk menimbulkan fitnah.\""}]};
